// Resolved entity sets (used to show per-card expand controls only after enrichment).
let __vkxResolvedUserIds = new Set<number>();
let __vkxResolvedGroupIds = new Set<number>();
let __vkxResolvedUserMap = new Map<number, any>();
let __vkxResolvedGroupMap = new Map<number, any>();

function __vkxCollectArr(v: any): any[] {
  if (!v) return [];
  if (Array.isArray(v)) return v;
  if (Array.isArray((v as any).users)) return (v as any).users;
  if (Array.isArray((v as any).groups)) return (v as any).groups;
  if (Array.isArray((v as any).items)) return (v as any).items;
  return [];
}

function __vkxRefreshResolvedSets(bundle: VkXtractBundle) {
  __vkxResolvedUserIds = new Set<number>();
  __vkxResolvedGroupIds = new Set<number>();
  __vkxResolvedUserMap = new Map<number, any>();
  __vkxResolvedGroupMap = new Map<number, any>();

  for (const run of (bundle.runs || [])) {
    if (!run || (run as any).ok !== true) continue;
    const act = String((run as any).action || '');
    const resp: any = (run as any).response;

    if (act === 'vkx.users.resolve' || act === 'users.get_group_contacts') {
      for (const u of __vkxCollectArr(resp)) {
        const id = Number((u as any)?.id);
        if (Number.isFinite(id) && id > 0) {
          const abs = Math.abs(id);
          __vkxResolvedUserIds.add(abs);
          __vkxResolvedUserMap.set(abs, u);
        }
      }
    }

    if (act === 'vkx.groups.resolve') {
      for (const g of __vkxCollectArr(resp)) {
        const id = Number((g as any)?.id);
        if (Number.isFinite(id) && id > 0) {
          const abs = Math.abs(id);
          __vkxResolvedGroupIds.add(abs);
          __vkxResolvedGroupMap.set(abs, g);
        }
      }
    }
  }
}

function esc(s: string): string {
  return String(s ?? '').replace(/[&<>"']/g, (c) => ({
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#39;'
  }[c] as string));
}

function fmtDate(ts: number): string {
  try { return new Date(ts).toLocaleString(); } catch { return String(ts); }
}
function csvCell(v: any): string {
  const s = (v == null) ? '' : String(v);
  // Escape quotes and wrap when needed
  if (/[",\n\r]/.test(s)) return `"${s.replace(/"/g, '""')}"`;
  return s;
}

function toCsv(rows: Array<Record<string, any>>, columns: string[]): string {
  const header = columns.map(csvCell).join(',');
  const lines = rows.map((r) => columns.map((c) => csvCell((r as any)[c])).join(','));
  return [header, ...lines].join('\n');
}

function dataHref(mime: string, content: string): string {
  return `data:${mime};charset=utf-8,${encodeURIComponent(content)}`;
}

function downloadLink(label: string, filename: string, mime: string, content: string): string {
  return `<a class="exportBtn" download="${esc(filename)}" href="${dataHref(mime, content)}">${esc(label)}</a>`;
}

function stableHash(input: string): number {
  // Simple deterministic hash for IDs
  let h = 0;
  for (let i = 0; i < input.length; i++) {
    h = ((h << 5) - h) + input.charCodeAt(i);
    h |= 0;
  }
  return Math.abs(h);
}

function enumLabel(v: any, map: Record<number, string>): string {
  const n = Number(v);
  if (!Number.isFinite(n) || n === 0) return t('report.common.notSpecified');
  return map[n] || t('report.common.unknownWithCode', { code: String(n) });
}


function groupAgeLimitsLabel(v: any): string {
  const n = Number(v);
  if (!Number.isFinite(n) || n === 0) return t('report.common.notSpecified');
  if (n === 1) return t('report.common.noAgeLimit');
  if (n === 2) return '16+';
  if (n === 3) return '18+';
  return t('report.common.unknownWithCode', { code: String(n) });
}

function groupMemberStatusLabel(v: any): string {
  const n = Number(v);
  if (!Number.isFinite(n)) return t('report.common.notSpecified');
  // VK docs: 0 not a member, 1 member, 2 not sure, 3 declined invite, 4 request sent, 5 invited
  if (n === 0) return t('report.common.notMemberLong');
  if (n === 1) return t('report.common.memberStatusShort');
  if (n === 2) return t('report.common.notSure');
  if (n === 3) return t('report.common.declinedInvitation');
  if (n === 4) return t('report.common.requestSent');
  if (n === 5) return t('report.common.invited');
  return t('report.common.unknownWithCode', { code: String(n) });
}

function normalizeFamilyRole(raw: any): string {
  return normalizeFamilyRoleCanonical(raw);
}

function translateContactRole(raw: string) {
  const r = String(raw || '').trim();
  if (!r) return '';
  const low = r.toLowerCase();
  const map: Record<string, string> = {
    'администратор сообщества': t('report.common.communityAdministrator'),
    'администратор': t('report.common.administrator'),
    'модератор': t('report.common.moderator'),
    'редактор': t('report.common.editor'),
    'руководитель': t('report.common.manager')
  };
  const key = Object.keys(map).find((k) => low === k || low.includes(k));
  if (key) return `${map[key]} (${r})`;
  return r;
}


