function groupContactCard(u: any, roleLabel: string, contact: any): string {
  const idVal = (u?.id != null ? u.id : (contact?.user_id ?? contact?.contact_id ?? contact?.id ?? '—'));
  const uidNum = Number(idVal);

  const name = [u?.first_name, u?.last_name].filter(Boolean).join(' ').trim()
    || (u?.name ? String(u.name) : (Number.isFinite(uidNum) ? `id${uidNum}` : '—'));

  const thumb = bestPhotoUrl(u);

  const domain = (u?.domain && String(u.domain).trim()) ? String(u.domain).trim() : '';
  const profileUrl = domain
    ? `https://vk.com/${domain}`
    : (Number.isFinite(uidNum) && uidNum > 0 ? `https://vk.com/id${uidNum}` : '');

  const isClosed = (u as any)?.is_closed;
  const closedPill = (isClosed === true || Number(isClosed) === 1) ? pill(t('report.common.profilePrivate'), 'bad') : pill(t('report.common.profileOpen'), 'ok');

  const tags: string[] = [];
  tags.push(closedPill);
  if (u?.deactivated) tags.push(pill(deactivatedLabel(u.deactivated), 'bad'));
  tags.push(pill(sexLabel(u?.sex)));

  const city = cityTitle(u);
  if (city && city !== '—') tags.push(pill(city));
  const country = countryTitle(u);
  const geoUnknown = (city === '—' && country === '—');
  const contactLat = Number(contact?.latitude ?? contact?.lat ?? contact?.geo_lat ?? contact?.geo?.latitude ?? NaN);
  const contactLon = Number(contact?.longitude ?? contact?.lon ?? contact?.lng ?? contact?.geo_lon ?? contact?.geo?.longitude ?? NaN);
  const hasDirectContactCoords = Number.isFinite(contactLat) && Number.isFinite(contactLon);
  const contactGeoBits = [
    contact?.address,
    contact?.city?.title,
    contact?.city,
    contact?.country?.title,
    contact?.country,
    contact?.location,
    contact?.place,
    contact?.office
  ].map((v) => String(v ?? '').trim()).filter(Boolean);
  const contactGeoQ = Array.from(new Set(contactGeoBits)).join(', ');
  const profileGeoQ = geoUnknown
    ? ''
    : (city !== '—' && country !== '—')
      ? `${city}, ${country}`
      : (city !== '—' ? city : country);
  const geoQ = contactGeoQ || profileGeoQ;
  const geoMissing = !geoQ && !hasDirectContactCoords;

  const detailId = `user:${String(idVal)}`;
  const isResolved = Number.isFinite(uidNum) && uidNum > 0 && __vkxResolvedUserIds.has(uidNum);
  const enrichIcon = isResolved ? '↻' : '⚡';
  const enrichText = isResolved ? t('report.common.reEnrichShort') : t('report.common.enrichShort');

  const actions: string[] = [];
  if (isResolved) actions.push(`<button class="vkxDropBtn" type="button" data-card-expand="${esc(detailId)}" aria-label="${esc(t('report.common.showDetails'))}" title="${esc(t('report.common.showDetails'))}">▾</button>`);
  if (profileUrl) actions.push(`<a class="vkxIconBtn" href="${esc(profileUrl)}" target="_blank" rel="noreferrer" title="${esc(t('report.common.linkToProfile'))}" aria-label="${esc(t('report.common.linkToProfile'))}">↗</a>`);
  if (Number.isFinite(uidNum) && uidNum > 0) actions.push(`<button class="gridLinkBtn" type="button" data-resolve-user="${esc(String(uidNum))}" data-resolve-full="1"><span class="gridLinkIcon">${enrichIcon}</span> ${enrichText}</button>`);

  const roleLine = roleLabel ? `<div><b>${esc(t('report.common.role'))}</b>: ${esc(String(roleLabel))}</div>` : '';

  const prettyKey = (k: string) => {
    const key = String(k || '').trim();
    const map: Record<string, string> = {
      phone: t('report.common.phone'),
      email: t('report.common.email'),
      telegram: 'Telegram',
      tg: 'Telegram',
      whatsapp: 'WhatsApp',
      viber: 'Viber',
      skype: 'Skype',
      instagram: 'Instagram',
      twitter: 'Twitter',
      facebook: 'Facebook',
      site: t('report.common.site')
    };
    return map[key] || key.replace(/_/g, ' ');
  };

  const extraLines: string[] = [];
  try {
    const skip = new Set(['user_id', 'contact_id', 'id', 'desc', 'position']);
    for (const k of Object.keys(contact || {})) {
      if (skip.has(k)) continue;
      const v = (contact as any)?.[k];
      if (v == null) continue;
      const s = String(v).trim();
      if (!s) continue;
      extraLines.push(`<div><b>${esc(prettyKey(k))}</b>: ${esc(s)}</div>`);
      if (extraLines.length >= 6) break;
    }
  } catch {}

  return `
    <div class="gridCard" data-card-key="${esc(detailId)}" data-group-contact="1" data-geo-q="${esc(geoQ)}" data-geo-unknown="${geoMissing ? '1' : '0'}"${hasDirectContactCoords ? ` data-geo-lat="${esc(String(contactLat))}" data-geo-lon="${esc(String(contactLon))}"` : ''}>
      <div class="gridThumb">
        ${thumb ? `<img src="${esc(thumb)}" alt="${esc(t('report.common.profileThumbnailAlt'))}" loading="lazy" referrerpolicy="no-referrer" />` : `<div class="thumbFallback">—</div>`}
      </div>
      <div class="gridBody">
        <div class="gridTitle">${esc(name)}</div>
        <div class="gridMeta">
          <div><b>${esc(t('report.common.userId'))}</b>: ${esc(String(idVal))}</div>
          ${roleLine}
          ${extraLines.join('')}
        </div>
        <div class="gridBadges">${tags.join(' ')}</div>
        ${actions.length ? `<div class="gridActions">${actions.join('')}</div>` : ''}
      </div>
    </div>
  `;
}

