function friendsSection(bundle: VkXtractBundle, opts?: { interactive?: boolean }): { html: string; count: number; label: string } {
  const isUser = bundle.target.kind === 'user';
  __vkxRefreshResolvedSets(bundle);

  const label = isUser ? t('report.enrichBar.friends') : t('report.common.members');
  const r = latestOkRun(bundle, (run) => run.action === (isUser ? 'friends.get' : 'groups.getMembers'));
  if (!r) return { html: `<div class="empty">${esc(t('report.common.noLabelExtractedYet', { label: label.toLowerCase() }))}</div>`, count: 0, label };

  const respAny: any = (r.response as any);
  const payload: any = respAny?.response ?? respAny;
  const itemsAll: any[] = Array.isArray(payload?.items) ? payload.items : [];
  const items = itemsAll;
  const total = Number(payload?.count ?? itemsAll.length);
  const capped = !!payload?.capped;

  const headerAction = (opts?.interactive)
    ? scopeEnrichControls('friends', label)
    : '';

  const header = `
    <div class="sectionHead">
      <div>
        <div class="sectionTitle">${esc(label)}</div>
        <div class="sectionSub">${esc(t('report.common.capturedAt', { value: fmtDate(r.ts) }))} • ${esc(t('report.common.showingOfTotal', {
          shown: items.length,
          totalPart: total ? t('report.common.totalPart', { total }) : '',
          cappedPart: capped ? t('report.common.cappedPart') : ''
        }))}</div>
      </div>
      ${headerAction}
    </div>
  `;

  if (!items.length) {
    return { html: header + `<div class="empty">${esc(t('report.common.noReturnedPrivateForLabel', { label: label.toLowerCase() }))}</div>`, count: 0, label };
  }

  const hasPlaces = items.some((u: any) => {
    const c = cityTitle(u);
    const k = countryTitle(u);
    return (c && c !== '—') || (k && k !== '—');
  });

  const mapHtml = (opts?.interactive && hasPlaces)
    ? `
      <div class="sectionCard" style="margin-top:12px;">
        <div class="cardTitle">${esc(label)} ${esc(t('report.common.locationsMap').toLowerCase())}</div>
        <div class="muted">${esc(t('report.common.approximateGeoViewportHint'))}</div>
        <div class="vkxMapWrap" style="position:relative;">
          <div id="vkxPeopleMap" class="vkxMap"></div>
        </div>
        <div id="vkxPeopleMapStatus" class="muted" style="margin-top:8px;">${esc(t('report.common.geocoding'))}</div>
        <div id="vkxPeopleMapDetail" class="vkxMapDetail"></div>
      </div>
    `
    : '';

  const cards = items.map((u: any) => userCard(u, t('report.common.user'))).join('');
  return { html: header + mapHtml + `<div class="grid" data-people-grid="1">${cards}</div>`, count: items.length, label };
}

