function giftThumb(g: any): string {
  const gift = g?.gift || g?.gift_info || g;
  return String(gift?.thumb_256 || gift?.thumb_96 || gift?.thumb_48 || gift?.thumb || gift?.image_256 || gift?.image || '');
}

function giftsSection(bundle: VkXtractBundle): { html: string; count: number } {
  const r = latestRun(bundle, (run) => run.action === 'gifts.get');
  if (!r) return { html: `<div class="empty">${esc(t('report.empty.noGiftsExtractedYet'))}</div>`, count: 0 };

  const header = `
    <div class="sectionHead">
      <div>
        <div class="sectionTitle">${esc(t('report.tabs.gifts'))}</div>
        <div class="sectionSub">${esc(t('report.common.capturedAt', { value: fmtDate(r.ts) }))}</div>
      </div>
    </div>
  `;

  if (!r.ok) {
    const err = JSON.stringify(r.error ?? {}, null, 2);
    return { html: header + `<div class="empty">${esc(t('report.common.giftsUnavailableDenied'))}</div><details style="margin-top:10px;"><summary>${esc(t('report.common.showError'))}</summary><pre>${esc(err)}</pre></details>`, count: 0 };
  }

  const resp: any = r.response as any;
  const items = Array.isArray(resp?.items) ? resp.items : (Array.isArray(resp) ? resp : []);
  const senders = Array.isArray(resp?.senders) ? resp.senders : [];
  const senderMap = new Map<number, any>();
  for (const u of senders) {
    const id = Number(u?.id);
    if (Number.isFinite(id)) senderMap.set(id, u);
  }

  if (!items.length) return { html: header + `<div class="empty">${esc(t('report.empty.noGiftsReturnedDenied'))}</div>`, count: 0 };

  const cards = items.map((g: any) => {
    const fromId = Number(g?.from_id);
    const sender = senderMap.get(fromId);
    const name = sender ? [sender.first_name, sender.last_name].filter(Boolean).join(' ').trim() : (fromId > 0 ? `${t('report.common.user')} ${fromId}` : t('report.common.anonymousHidden'));
    const photo = sender ? (sender.photo_100 || sender.photo_200 || '') : '';
    const date = g?.date ? fmtDate(Number(g.date) * 1000) : '—';
    const msg = g?.message ? String(g.message) : '';
    const thumb = giftThumb(g);
    return `
      <div class="gridCard">
        <div class="gridThumb">
          ${thumb ? `<img src="${esc(thumb)}" alt="${esc(t('report.common.giftThumbnailAlt'))}" loading="lazy" />` : `<div class="thumbFallback">—</div>`}
        </div>
        <div class="gridBody">
          <div class="gridTitle">${esc(name)}</div>
          <div class="gridMeta">
            <div><b>${esc(t('report.common.dateLabel'))}</b>: ${esc(date)}</div>
            ${fromId > 0 ? `<div><b>${esc(t('report.common.fromIdLabel'))}</b>: ${esc(String(fromId))}</div>` : ''}
          </div>
          ${msg ? `<div class="gridText">${esc(msg)}</div>` : ''}
          ${photo ? `<div style="margin-top:8px;"><img class="miniAvatar" src="${esc(photo)}" alt="${esc(t('report.common.senderAlt'))}" loading="lazy" /></div>` : ''}
        </div>
      </div>
    `;
  }).join('');

  return { html: header + `<div class="grid">${cards}</div>`, count: items.length };
}

