// For the extension report page: return style + body markup (no <html>/<head> wrapper).
export function renderReportApp(bundle: VkXtractBundle, opts?: { interactive?: boolean; brandLogoDataUrl?: string; appLogoDataUrl?: string }): string {
  const full = renderReport(bundle, opts);
  const styleMatch = full.match(/<style>[\s\S]*?<\/style>/i);
  const bodyMatch = full.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
  const style = styleMatch ? styleMatch[0] : '';
  const body = bodyMatch ? bodyMatch[1] : full;
  return `${style}\n${body}`;
}
