import { en } from './en';
import { uk } from './uk';

export type Locale = 'en' | 'uk';

const STORAGE_KEY = 'vkxtract-popup-locale';

const dictionaries = { en, uk } as const;

let currentLocale: Locale = 'en';

function getNested(obj: any, path: string): any {
  return path.split('.').reduce((acc, key) => (acc == null ? undefined : acc[key]), obj);
}

export function loadLocale(): Locale {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw === 'uk' || raw === 'en') currentLocale = raw;
  } catch {
    currentLocale = 'en';
  }
  return currentLocale;
}

export function getLocale(): Locale {
  return currentLocale;
}

export function setLocale(locale: Locale) {
  currentLocale = locale;
  try {
    localStorage.setItem(STORAGE_KEY, locale);
  } catch {
    // ignore
  }
}

export function t(path: string, vars?: Record<string, any>): string {
  let value = getNested(dictionaries[currentLocale], path);
  if (typeof value !== 'string') value = getNested(dictionaries.en, path);
  if (typeof value !== 'string') return path;

  if (vars && typeof vars === 'object') {
    for (const [k, v] of Object.entries(vars)) {
      value = value.replaceAll(`{${k}}`, String(v));
    }
  }
  return value;
}