export type Scope = 'photo' | 'video' | 'observed';

export type LcVisNodeIn = {
  key: string;
  kind: 'user' | 'media' | 'post';
  label: string;
  thumb?: string;
  x?: number;
  y?: number;
};

export type LcVisEdgeIn = {
  edgeId: string;
  a: string;
  b: string;
  liked: boolean;
  copied: boolean;
  commentCount: number;
  replyCount?: number;
};

type VisDataSet<T> = {
  getIds(): Array<string | number>;
  update(items: Partial<T>[]): void;
};

type VisNetwork = {
  destroy(): void;
  on(event: string, cb: (params: any) => void): void;
  fit(opts?: unknown): void;
  moveTo(opts: unknown): void;
  getScale(): number;
  setOptions(opts: unknown): void;
  unselectAll(): void;
  startSimulation?(): void;
  stopSimulation?(): void;
};

type VisModule = {
  DataSet: new <T>(items: T[]) => VisDataSet<T>;
  Network: new (container: HTMLElement, data: unknown, options: unknown) => VisNetwork;
};

function getVis(): VisModule | null {
  const w = window as unknown as { vis?: unknown };
  const v = w.vis as VisModule | undefined;
  if (!v) return null;
  const vv = v as unknown as Record<string, unknown>;
  if (typeof vv !== 'object' || !vv) return null;
  if (!('Network' in vv) || !('DataSet' in vv)) return null;
  return v;
}

export function lcVisAvailable(): boolean {
  return !!getVis();
}

function noteObservedPointerActivity(scope: Scope, st: any, ms = 260) {
  if (scope !== 'observed') return;
  (st as any).__vkxObservedPointerBusyUntil = Date.now() + Math.max(120, Number(ms || 0));
}

function edgeLongLabel(e: LcVisEdgeIn): string {
  const bits: string[] = [];
  if (e.liked) bits.push('Liked');
  if (e.commentCount > 0) bits.push(`Commented${e.commentCount > 1 ? `×${e.commentCount}` : ''}`);
  if (Number(e.replyCount || 0) > 0) bits.push(`Replied${Number(e.replyCount || 0) > 1 ? `×${Number(e.replyCount || 0)}` : ''}`);
  if (e.copied) bits.push('Copied');
  return bits.join(' • ') || '';
}

function postNodeIconDataUri(): string {
  const svg =
    `<svg xmlns="http://www.w3.org/2000/svg" width="64" height="64" viewBox="0 0 64 64">
      <defs>
        <linearGradient id="g" x1="0" x2="1" y1="0" y2="1">
          <stop offset="0%" stop-color="#f59e0b"/>
          <stop offset="100%" stop-color="#fb7185"/>
        </linearGradient>
      </defs>
      <rect x="4" y="4" width="56" height="56" rx="18" fill="url(#g)"/>
      <rect x="18" y="18" width="28" height="4" rx="2" fill="white" opacity="0.95"/>
      <rect x="18" y="28" width="20" height="4" rx="2" fill="white" opacity="0.9"/>
      <rect x="18" y="38" width="24" height="4" rx="2" fill="white" opacity="0.85"/>
    </svg>`;
  return `data:image/svg+xml;charset=UTF-8,${encodeURIComponent(svg)}`;
}

export function lcVisUpsert(scope: Scope, st: any, nodesIn: LcVisNodeIn[], edgesIn: LcVisEdgeIn[]) {
  const v = st?.vis;
  if (!v?.network || !v?.nodes || !v?.edges) return false;

  const prevNodeIds = new Set<string>();
  const prevEdgeIds = new Set<string>();
  try {
    for (const id of v.nodes.getIds()) prevNodeIds.add(String(id));
    for (const id of v.edges.getIds()) prevEdgeIds.add(String(id));
  } catch {}

  const nodes = nodesIn.map((n) => {
    const labelFull = String(n.label || '');
    const commonFont = {
      size: 11,
      face: 'system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif',
      color: 'rgba(231,238,252,0.92)',
      background: 'rgba(0,0,0,0.32)'
    };

    if (n.kind === 'media') {
      return {
        id: n.key,
        label: '',
        labelFull,
        title: labelFull,
        shape: 'circularImage',
        image: n.thumb || '',
        size: 28,
        borderWidth: 2,
        color: { border: 'rgba(0,0,0,0.35)', background: 'rgba(0,0,0,0)' },
        font: commonFont,
        x: Number.isFinite(Number(n.x)) ? Number(n.x) : undefined,
        y: Number.isFinite(Number(n.y)) ? Number(n.y) : undefined
      };
    }

    if (n.kind === 'post') {
      return {
        id: n.key,
        label: '',
        labelFull,
        title: labelFull,
        shape: 'circularImage',
        image: postNodeIconDataUri(),
        size: 24,
        borderWidth: 2,
        color: { border: 'rgba(245,158,11,0.55)', background: 'rgba(0,0,0,0)' },
        font: commonFont,
        x: Number.isFinite(Number(n.x)) ? Number(n.x) : undefined,
        y: Number.isFinite(Number(n.y)) ? Number(n.y) : undefined
      };
    }

    return {
      id: n.key,
      label: labelFull,
      labelFull,
      title: labelFull,
      shape: 'dot',
      size: 9,
      color: { background: 'rgba(99,102,241,0.92)', border: 'rgba(0,0,0,0.35)' },
      font: commonFont,
      x: Number.isFinite(Number(n.x)) ? Number(n.x) : undefined,
      y: Number.isFinite(Number(n.y)) ? Number(n.y) : undefined
    };
  });

  const edges = edgesIn.map((e) => ({
    id: e.edgeId,
    from: e.a,
    to: e.b,
    label: '',
    labelFull: edgeLongLabel(e),
    width: 1.1,
    color: { color: 'rgba(231,238,252,0.18)' },
    font: {
      size: 11,
      face: 'system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif',
      color: 'rgba(231,238,252,0.80)',
      background: 'rgba(0,0,0,0.28)',
      align: 'middle'
    }
  }));

  const nextNodeIds = new Set(nodes.map((n: any) => String(n.id)));
  const nextEdgeIds = new Set(edges.map((e: any) => String(e.id)));
  const removedNodeIds = Array.from(prevNodeIds).filter((id) => !nextNodeIds.has(id));
  const removedEdgeIds = Array.from(prevEdgeIds).filter((id) => !nextEdgeIds.has(id));
  const addedNodeIds = nodes.map((n: any) => String(n.id)).filter((id) => !prevNodeIds.has(id));
  const addedEdgeIds = edges.map((e: any) => String(e.id)).filter((id) => !prevEdgeIds.has(id));
  const topologyChanged = !!(addedNodeIds.length || removedNodeIds.length || addedEdgeIds.length || removedEdgeIds.length);

  try { if (removedEdgeIds.length) (v.edges as any).remove?.(removedEdgeIds as any); } catch {}
  try { if (removedNodeIds.length) (v.nodes as any).remove?.(removedNodeIds as any); } catch {}

  try { v.nodes.update(nodes as any); } catch {}
  try { v.edges.update(edges as any); } catch {}

  try {
    for (const n of nodes as any[]) {
      v.baseNodes[String(n.id)] = { color: n.color, font: n.font, size: n.size, borderWidth: n.borderWidth };
    }
    for (const e of edges as any[]) {
      v.baseEdges[String(e.id)] = { color: e.color, width: e.width, font: e.font, label: (e as any).labelFull || '' };
    }
    for (const id of removedNodeIds) delete v.baseNodes[String(id)];
    for (const id of removedEdgeIds) delete v.baseEdges[String(id)];
  } catch {}

  if (topologyChanged) {
    try {
      const allNodeIds = Array.from(nextNodeIds.values());
      if (allNodeIds.length) {
        v.nodes.update(allNodeIds.map((id: string) => ({ id, fixed: false, physics: true })) as any);
      }
    } catch {}

    try {
      if ((v as any).__vkxPhysicsStopTimer) window.clearTimeout((v as any).__vkxPhysicsStopTimer);
    } catch {}

    try {
      (v.network as any).setOptions?.({
        layout: { hierarchical: { enabled: false } },
        physics: {
          enabled: true,
          solver: 'barnesHut',
          barnesHut: { gravitationalConstant: -4200, springLength: 240, springConstant: 0.03, damping: 0.55 },
          stabilization: false,
          timestep: 0.5,
          minVelocity: 0.75
        }
      });
    } catch {}

    if (scope !== 'observed') {
      window.setTimeout(() => {
        try { (v.network as any).fit?.({ animation: false }); } catch {}
        try { (v.network as any).startSimulation?.(); } catch {}
      }, 0);

      try {
        (v as any).__vkxPhysicsStopTimer = window.setTimeout(() => {
          try { (v.network as any).stopSimulation?.(); } catch {}
          try { (v.network as any).setOptions?.({ physics: { enabled: false } }); } catch {}
          try { (v.network as any).fit?.({ animation: { duration: 260 } }); } catch {}
        }, 1400);
      } catch {}
    }
  }

  return true;
}
export function lcVisBuild(
  scope: Scope,
  container: HTMLElement,
  nodesIn: LcVisNodeIn[],
  edgesIn: LcVisEdgeIn[],
  st: { movable: boolean; vis?: any; adj?: Record<string, string[]> },
  handlers: {
    onEdge?: (edgeId: string) => void;
    onSelection?: (nodeIds: string[], lastId: string, mods?: { ctrl: boolean; meta: boolean; shift: boolean }) => void;
    onNodeDbl?: (nodeId: string) => void;
    onClear?: () => void;
    onHoverMedia?: (nodeId: string) => void;
    onBlurMedia?: () => void;
  }
): boolean {
  const vis = getVis();
  if (!vis) return false;

  // clean destroy previous
  try {
    const prev = (st.vis?.network as VisNetwork | undefined);
    prev?.destroy?.();
  } catch {}

  container.innerHTML = `
    <div class="lcVisHost" data-lc-vis="${scope}" style="width:100%;height:100%;min-height:420px;touch-action:none;"></div>
    <div class="lcOverlay" data-lc-overlay="${scope}"></div>
  `;

  const host = container.querySelector(`[data-lc-vis="${scope}"]`) as HTMLElement | null;
  if (!host) return false;

  const nodes = nodesIn.map((n) => {
    const labelFull = String(n.label || '');
    const commonFont = {
      size: 11,
      face: 'system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif',
      color: 'rgba(231,238,252,0.92)',
      background: 'rgba(0,0,0,0.32)'
    };
    const xy = {
      x: Number.isFinite(Number(n.x)) ? Number(n.x) : undefined,
      y: Number.isFinite(Number(n.y)) ? Number(n.y) : undefined
    };

    if (n.kind === 'media') {
      return {
        id: n.key,
        label: '',
        labelFull,
        title: labelFull,
        shape: 'circularImage',
        image: n.thumb || '',
        size: 28,
        borderWidth: 2,
        color: { border: 'rgba(0,0,0,0.35)', background: 'rgba(0,0,0,0)' },
        font: commonFont,
        ...xy
      };
    }

    if (n.kind === 'post') {
      return {
        id: n.key,
        label: '',
        labelFull,
        title: labelFull,
        shape: 'circularImage',
        image: postNodeIconDataUri(),
        size: 24,
        borderWidth: 2,
        color: { border: 'rgba(245,158,11,0.55)', background: 'rgba(0,0,0,0)' },
        font: commonFont,
        ...xy
      };
    }

    return {
      id: n.key,
      label: labelFull,
      labelFull,
      shape: 'dot',
      size: 9,
      color: { background: 'rgba(99,102,241,0.92)', border: 'rgba(0,0,0,0.35)' },
      font: commonFont,
      ...xy
    };
  });

  const edges = edgesIn.map((e) => ({
    id: e.edgeId,
    from: e.a,
    to: e.b,
    label: '',
    labelFull: edgeLongLabel(e),
    width: 1.1,
    color: { color: 'rgba(231,238,252,0.18)' },
    font: {
      size: 11,
      face: 'system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif',
      color: 'rgba(231,238,252,0.80)',
      background: 'rgba(0,0,0,0.28)',
      align: 'middle'
    }
  }));

  const nodesDs = new vis.DataSet(nodes);
  const edgesDs = new vis.DataSet(edges);

  // Store base styles so we can dim/highlight without losing original look
  const baseNodes: Record<string, any> = {};
  for (const id of nodesDs.getIds()) {
    const n: any = (nodesDs as any).get?.(id);
    baseNodes[String(id)] = { color: n?.color, font: n?.font, size: n?.size, borderWidth: n?.borderWidth };
  }
  const baseEdges: Record<string, any> = {};
  for (const id of edgesDs.getIds()) {
    const e: any = (edgesDs as any).get?.(id);
    baseEdges[String(id)] = { color: e?.color, width: e?.width, font: e?.font, label: e?.labelFull || '' };
  }

  const options = {
    autoResize: true,
    nodes: { borderWidthSelected: 3 },
    edges: { smooth: { enabled: false }, selectionWidth: 2.2 },
    interaction: {
      hover: true,
      hoverConnectedEdges: false,
      selectConnectedEdges: false,
      zoomView: true,
      dragView: true,
      dragNodes: !!st.movable,
      multiselect: true
    },

    // Default layout is radial; report.ts toggles to bipartite via setOptions.
    layout: { hierarchical: { enabled: false } },
    physics: {
      enabled: true,
      solver: 'barnesHut',
      barnesHut: { gravitationalConstant: -4200, springLength: 240, springConstant: 0.03, damping: 0.55 },
      stabilization: false,
      timestep: 0.5,
      minVelocity: 0.75
    }
  };

  const network = new vis.Network(host, { nodes: nodesDs, edges: edgesDs }, options);

  if (scope === 'observed') {
    const markObservedPointer = () => {
      noteObservedPointerActivity(scope, st, 280);
    };

    try { host.addEventListener('pointermove', markObservedPointer, { passive: true }); } catch {}
    try { host.addEventListener('wheel', markObservedPointer, { passive: true }); } catch {}
    try { host.addEventListener('pointerdown', markObservedPointer, { passive: true }); } catch {}
    try { host.addEventListener('contextmenu', markObservedPointer); } catch {}
    try { host.addEventListener('touchstart', markObservedPointer, { passive: true }); } catch {}
  }

  try {
    if ((st as any).__vkxBuildPhysicsStopTimer) window.clearTimeout((st as any).__vkxBuildPhysicsStopTimer);
  } catch {}

  if (scope !== 'observed') {
    window.setTimeout(() => {
      try { (network as any).fit?.({ animation: false }); } catch {}
      try { (network as any).startSimulation?.(); } catch {}
    }, 0);

    try {
      (st as any).__vkxBuildPhysicsStopTimer = window.setTimeout(() => {
        try { (network as any).stopSimulation?.(); } catch {}
        try { (network as any).setOptions?.({ physics: { enabled: false } }); } catch {}
        try { (network as any).fit?.({ animation: { duration: 260 } }); } catch {}
      }, 1400);
    } catch {}
  }
  
  // Labels: hidden by default; show only on hover or selection
  let hoverNodeId = '';

  const syncNodeLabels = () => {
    try {
      const selected: any[] = (network as any).getSelectedNodes?.() || [];
      const show = new Set<string>(selected.map((x) => String(x)));
      const allowObservedHoverLabels = !(scope === 'observed' && !(st as any)?.__vkxObservedHoverReady);

      if (hoverNodeId && allowObservedHoverLabels) show.add(hoverNodeId);

      const upd: any[] = [];
      for (const id of nodesDs.getIds()) {
        const sid = String(id);
        const n: any = (nodesDs as any).get?.(sid) || {};
        const full = String(n.labelFull || '');
        const want = sid.startsWith('u:') ? full : (show.has(sid) ? full : '');
        if (String(n.label || '') !== want) upd.push({ id: sid, label: want });
      }
      if (upd.length) nodesDs.update(upd);
    } catch {}
  };

  const applyEdgeWidthForScale = () => {
    try {
      const s = Math.max(0.25, Math.min(3.0, Number((network as any).getScale?.() || 1)));
      // Zoomed out (s<1) => thicker. Zoomed in => near base.
      const factor = Math.max(0.9, Math.min(3.0, 1 / Math.pow(s, 0.85)));
      const upd: any[] = [];
      for (const id of edgesDs.getIds()) {
        const base = (baseEdges[String(id)]?.width ?? 1.1);
        upd.push({ id, width: Math.max(0.9, Math.min(3.2, base * factor)) });
      }
      edgesDs.update(upd);
    } catch {}
  };

  // Apply now and whenever zoom changes
  applyEdgeWidthForScale();
  try { (network as any).on('zoom', applyEdgeWidthForScale); } catch {}

  // Right-click context menu support
  try {
    host.addEventListener('contextmenu', (ev) => {
      ev.preventDefault();

      const nodeId = String((network as any).getNodeAt?.({ x: ev.offsetX, y: ev.offsetY }) || '');
      if (!nodeId) return;

      // Always select on right-click so highlight matches context
      try { (network as any).selectNodes?.([nodeId]); } catch {}
      handlers.onSelection?.([nodeId], nodeId, { ctrl: false, meta: false, shift: false });

      const ctx = document.getElementById('vkxLcCtx') as HTMLElement | null;
      if (!ctx) return;
      ctx.setAttribute('data-lcctx-node', nodeId);
      ctx.setAttribute('data-lcctx-scope', scope);

      ctx.style.left = `${Math.min(window.innerWidth - 210, ev.clientX)}px`;
      ctx.style.top = `${Math.min(window.innerHeight - 160, ev.clientY)}px`;
      ctx.style.display = 'block';
    });
  } catch {}

  network.on('selectEdge', (p) => {
    const id = p?.edges?.[0];
    if (id && handlers.onEdge) handlers.onEdge(String(id));
  });

  const emitSelection = (p: any, lastId: string) => {
    try {
      const se: any = p?.event?.srcEvent;
      const mods = { ctrl: !!se?.ctrlKey, meta: !!se?.metaKey, shift: !!se?.shiftKey };
      const ids = (network as any).getSelectedNodes?.() || p?.nodes || [];
      const nodeIds = Array.isArray(ids) ? ids.map((x: any) => String(x)) : [];
      handlers.onSelection?.(nodeIds, String(lastId || ''), mods);
    } catch {
      handlers.onSelection?.([], '', { ctrl: false, meta: false, shift: false });
    }
  };

  network.on('selectNode', (p: any) => {
    const lastId = String(p?.nodes?.[0] || '');
    emitSelection(p, lastId);
    syncNodeLabels();
  });

  network.on('deselectNode', (p: any) => {
    emitSelection(p, '');
    syncNodeLabels();
  });

  network.on('click', (p) => {
    if (!p?.nodes?.length && !p?.edges?.length) handlers.onClear?.();
  });

  network.on('hoverNode', (p: any) => {
    const id = String(p?.node || p?.nodes?.[0] || '');
    if (scope === 'observed' && id) noteObservedPointerActivity(scope, st, 320);
    hoverNodeId = id || '';
    syncNodeLabels();
    if (id) handlers.onHoverMedia?.(id);
  });

  network.on('blurNode', () => {
    hoverNodeId = '';
    syncNodeLabels();
    handlers.onBlurMedia?.();
  });

    // Persist dragged node positions (prevents physics snapping them back)
  try {
    (network as any).on('dragStart', (p: any) => {
      if (!st?.movable) return;
      const ids: any[] = Array.isArray(p?.nodes) ? p.nodes : [];
      if (!ids.length) return;

      try {
        if ((st as any).__vkxDragPhysicsStopTimer) window.clearTimeout((st as any).__vkxDragPhysicsStopTimer);
      } catch {}

      if (scope === 'observed') {
        (st as any).__vkxObservedUserInteracted = true;
        const upd = ids.map((id: any) => ({ id: String(id), fixed: false, physics: true }));
        try { nodesDs.update(upd as any); } catch {}
        try { (network as any).setOptions?.({ interaction: { dragNodes: true, dragView: true } }); } catch {}
        return;
      }

      const upd = ids.map((id: any) => ({ id: String(id), fixed: false, physics: true }));
      try { nodesDs.update(upd as any); } catch {}
      try { (network as any).setOptions?.({ interaction: { dragNodes: true, dragView: true } }); } catch {}
    });

    (network as any).on('dragEnd', (p: any) => {
      if (!st?.movable) return;

      const ids: any[] = Array.isArray(p?.nodes) ? p.nodes : [];
      if (!ids.length) return;

      const pos = (network as any).getPositions?.(ids) || {};

      if (scope === 'observed') {
        const linked = new Set<string>();
        for (const rawId of ids) {
          const pid = String(rawId);
          const neighbours = Array.isArray(st?.adj?.[pid]) ? st.adj[pid] : [];
          for (const nb of neighbours) {
            const nid = String(nb);
            if (nid && nid !== pid) linked.add(nid);
          }
        }

        const draggedUpd = ids.map((id: any) => {
          const pid = String(id);
          const xy = pos[pid];
          if (!xy) return { id: pid, fixed: { x: true, y: true }, physics: false };
          return { id: pid, x: xy.x, y: xy.y, fixed: { x: true, y: true }, physics: false };
        });
        const linkedUpd = Array.from(linked.values()).map((id) => ({ id, fixed: false, physics: true }));

        nodesDs.update(draggedUpd as any);
        if (linkedUpd.length) nodesDs.update(linkedUpd as any);

        try {
          if ((st as any).__vkxDragPhysicsStopTimer) window.clearTimeout((st as any).__vkxDragPhysicsStopTimer);
        } catch {}

        try {
          (network as any).setOptions?.({
            layout: { hierarchical: { enabled: false } },
            physics: {
              enabled: true,
              solver: 'barnesHut',
              barnesHut: { gravitationalConstant: -4200, springLength: 180, springConstant: 0.03, damping: 0.55 },
              stabilization: false,
              timestep: 0.5,
              minVelocity: 0.75
            }
          });
        } catch {}

        window.setTimeout(() => {
          try { (network as any).startSimulation?.(); } catch {}
        }, 0);

        try {
          (st as any).__vkxDragPhysicsStopTimer = window.setTimeout(() => {
            try { (network as any).stopSimulation?.(); } catch {}
            try { (network as any).setOptions?.({ physics: { enabled: false } }); } catch {}
            try { nodesDs.update(Array.from(linked.values()).map((id) => ({ id, fixed: false, physics: false })) as any); } catch {}
          }, 950);
        } catch {}
        return;
      }

      const linked = new Set<string>();
      for (const rawId of ids) {
        const pid = String(rawId);
        const neighbours = Array.isArray(st?.adj?.[pid]) ? st.adj[pid] : [];
        for (const nb of neighbours) {
          const nid = String(nb);
          if (nid && nid !== pid) linked.add(nid);
        }
      }

      const draggedUpd = ids.map((id: any) => {
        const pid = String(id);
        const xy = pos[pid];
        if (!xy) return { id: pid, fixed: { x: true, y: true }, physics: false };
        return { id: pid, x: xy.x, y: xy.y, fixed: { x: true, y: true }, physics: false };
      });
      const linkedUpd = Array.from(linked.values()).map((id) => ({ id, fixed: false, physics: true }));

      nodesDs.update(draggedUpd as any);
      if (linkedUpd.length) nodesDs.update(linkedUpd as any);

      try {
        if ((st as any).__vkxDragPhysicsStopTimer) window.clearTimeout((st as any).__vkxDragPhysicsStopTimer);
      } catch {}

      try {
        (network as any).setOptions?.({
          layout: { hierarchical: { enabled: false } },
          physics: {
            enabled: true,
            solver: 'barnesHut',
            barnesHut: { gravitationalConstant: -4200, springLength: 240, springConstant: 0.03, damping: 0.55 },
            stabilization: false,
            timestep: 0.5,
            minVelocity: 0.75
          }
        });
      } catch {}

      window.setTimeout(() => {
        try { (network as any).startSimulation?.(); } catch {}
      }, 0);

      try {
        (st as any).__vkxDragPhysicsStopTimer = window.setTimeout(() => {
          try { (network as any).stopSimulation?.(); } catch {}
          try { (network as any).setOptions?.({ physics: { enabled: false } }); } catch {}
          try { nodesDs.update(Array.from(linked.values()).map((id) => ({ id, fixed: false, physics: false })) as any); } catch {}
        }, 1100);
      } catch {}
    });
  } catch {}

  st.vis = { network, nodes: nodesDs, edges: edgesDs, baseNodes, baseEdges };
  return true;
}

export function lcVisFit(st: { vis?: { network: unknown } }) {
  try { (st.vis?.network as VisNetwork | undefined)?.fit?.({ animation: { duration: 220 } }); } catch {}
}

export function lcVisZoom(st: { vis?: { network: unknown } }, factor: number) {
  try {
    const net = (st.vis?.network as VisNetwork | undefined);
    if (!net) return;
    const cur = Number(net.getScale?.() || 1);
    const next = Math.max(0.2, Math.min(3.0, cur * factor));
    net.moveTo?.({ scale: next, animation: { duration: 140 } });
  } catch {}
}

export function lcVisSetMove(st: { vis?: { network: unknown } }, movable: boolean) {
  try {
    const net = (st.vis?.network as VisNetwork | undefined);
    if (!net) return;
    net.setOptions?.({ interaction: { dragNodes: !!movable } });
  } catch {}
}

type VisNode = { id: string; label?: string; color?: any; font?: any; size?: number; borderWidth?: number };
type VisEdge = { id: string; color?: any; width?: number; font?: any };

export function lcVisGetNodeDomPoint(st: { vis?: { network: unknown } }, nodeId: string): { x: number; y: number } | null {
  try {
    const net: any = st.vis?.network;
    if (!net) return null;
    const pos = net.getPositions?.([nodeId])?.[nodeId];
    if (!pos) return null;
    const dom = net.canvasToDOM?.(pos);
    if (!dom) return null;
    return { x: Number(dom.x || 0), y: Number(dom.y || 0) };
  } catch {
    return null;
  }
}

function dimFont(base: any) {
  return {
    ...(base || {}),
    color: 'rgba(231,238,252,0.35)',
    background: 'rgba(0,0,0,0.22)',
    strokeWidth: 0
  };
}

function hiFont(base: any) {
  return {
    ...(base || {}),
    color: 'rgba(231,238,252,0.92)',
    background: 'rgba(0,0,0,0.32)',
    strokeWidth: 0
  };
}

function hueFromKey(k: string): number {
  const s = String(k || '');
  let h = 0;
  for (let i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) >>> 0;
  return h % 360;
}
function hi1(h: number) { return `hsla(${h}, 92%, 60%, 0.55)`; }
function hi2(h: number) { return `hsla(${h}, 92%, 60%, 0.35)`; }
function solid(h: number) { return `hsl(${h}, 92%, 60%)`; }

export function lcVisApplyFocus(scope: Scope, st: any) {
  const net: any = st?.vis?.network;
  const nodesDs: any = st?.vis?.nodes;
  const edgesDs: any = st?.vis?.edges;
  const baseNodes: Record<string, any> = st?.vis?.baseNodes || {};
  const baseEdges: Record<string, any> = st?.vis?.baseEdges || {};
  if (!net || !nodesDs || !edgesDs) return;

  const sel = String(st?.sel || '');
  const focusOn = !!st?.focusOn;

  const selKeys: string[] = Array.isArray(st?.selKeys) ? st.selKeys.map((x: any) => String(x)) : [];
  const seeds = selKeys.length ? selKeys : (sel ? [sel] : []);

  const hoverKey = String(st?.hoverKey || '');
  const accentKey =
    (hoverKey && hoverKey.startsWith('m:')) ? hoverKey :
    (sel && sel.startsWith('m:')) ? sel :
    `${scope}:default`;

  const h = hueFromKey(accentKey);
  const edgeHi1 = hi1(h);
  const edgeHi2 = hi2(h);
  const borderHi = { border: solid(h), background: 'rgba(0,0,0,0)' };
  const borderSoft = { border: hi2(h), background: 'rgba(0,0,0,0)' };

  // Restore baseline
  if (!focusOn || !seeds.length) {
    const nUpd: any[] = [];
    for (const id of nodesDs.getIds()) {
      const sid = String(id);
      const b = baseNodes[sid] || {};
      nUpd.push({ id, color: b.color, font: b.font, size: b.size, borderWidth: b.borderWidth });
    }
    nodesDs.update(nUpd);

    const eUpd: any[] = [];
    for (const id of edgesDs.getIds()) {
      const sid = String(id);
      const b = baseEdges[sid] || {};
      eUpd.push({ id: sid, color: b.color, width: b.width, font: b.font, label: '' });
    }
    edgesDs.update(eUpd);

    return;
  }

  const adj: Record<string, string[]> = st.adj || {};
  const n1 = new Set<string>();
  const n2 = new Set<string>();

  for (const s of seeds) {
    for (const n of (adj[s] || [])) n1.add(n);
  }

  if (Number(st.focusDepth || 1) === 2) {
    for (const a of n1) {
      for (const b of (adj[a] || [])) {
        if (b !== sel && !n1.has(b)) n2.add(b);
      }
    }
  }

  // Nodes update (+ media glow using accent colour)
  const nUpd: any[] = [];
  for (const id of nodesDs.getIds()) {
    const sid = String(id);
    const base = baseNodes[sid] || {};
    const isActive = (sid === sel || n1.has(sid) || n2.has(sid));
    const font = isActive ? hiFont(base.font) : dimFont(base.font);

    let color = base.color;
    if (sid.startsWith('m:')) {
      if (sid === accentKey) color = { ...(base.color || {}), ...borderHi };
      else if (isActive && (n1.has(sid) || n2.has(sid))) color = { ...(base.color || {}), ...borderSoft };
    }

    nUpd.push({ id: sid, font, color });
  }
  nodesDs.update(nUpd);

  // Edges update (edgeEnds provided by report.ts)
  const edgeEnds: Record<string, { a: string; b: string }> = st.edgeEnds || {};
  const eUpd: any[] = [];

  for (const id of edgesDs.getIds()) {
    const eid = String(id);
    const base = baseEdges[eid] || {};
    const ends = edgeEnds[eid];

    const labelSeeds = new Set<string>(seeds);

    if (!ends) {
      eUpd.push({ id: eid, color: { color: 'rgba(231,238,252,0.10)' }, width: 1.0, font: dimFont(base.font), label: '' });
      continue;
    }

    const a = ends.a;
    const b = ends.b;

    const showLabel = labelSeeds.has(a) || labelSeeds.has(b);
    const edgeLabel = showLabel ? String(base.label || '') : '';

    if (seeds.includes(a) || seeds.includes(b)) {
      eUpd.push({ id: eid, color: { color: edgeHi1 }, width: 2.2, font: hiFont(base.font), label: edgeLabel });
      continue;
    }

    if (Number(st.focusDepth || 1) === 2) {
      const inN1 = n1.has(a) || n1.has(b);
      const inN2 = n2.has(a) || n2.has(b);
      if (inN1 && inN2) {
        eUpd.push({ id: eid, color: { color: edgeHi2 }, width: 1.7, font: hiFont(base.font), label: edgeLabel });
        continue;
      }
    }

    eUpd.push({ id: eid, color: { color: 'rgba(231,238,252,0.10)' }, width: 1.0, font: dimFont(base.font), label: edgeLabel });
  }

  edgesDs.update(eUpd);
}

export function lcVisClear(st: { vis?: { network: unknown } }) {
  try { (st.vis?.network as VisNetwork | undefined)?.unselectAll?.(); } catch {}
}