function enrichProgPct(p: any): number {
  if (!p || typeof p !== 'object') return 0;
  const total = Number((p as any).total ?? 0);
  const done = Number((p as any).done_count ?? (p as any).doneCount ?? 0);
  const cap = total > 0 ? total : 0;
  if (!Number.isFinite(done) || done < 0 || !Number.isFinite(cap) || cap <= 0) return 0;
  return Math.max(0, Math.min(100, Math.round((done / cap) * 100)));
}

function enrichProgSummary(p: any): string {
  if (!p || typeof p !== 'object') return '';
  const total = Number((p as any).total ?? 0);
  const done = Number((p as any).done_count ?? (p as any).doneCount ?? 0);
  const cap = total > 0 ? total : 0;
  const anyDenied = Number((p as any).denied_any_count ?? 0);
  const backoff = Number((p as any).backoff_sec ?? 0);
  const parts: string[] = [];
  if (Number.isFinite(done) && done >= 0) parts.push(`${done}/${cap}`);
  if (Number.isFinite(anyDenied) && anyDenied > 0) parts.push(`denied:${anyDenied}`);
  if (Number.isFinite(backoff) && backoff > 0) parts.push(`backoff:${backoff}s`);
  return parts.join(' • ');
}

function updateGlobalEnrichBar() {
  const bar = document.getElementById('vkxGlobalEnrichBar') as HTMLElement | null;
  if (!bar) return;

  const ctl = (window as any).__vkxEnrichCtl || {};
  const scopes = ['photos', 'videos', 'friends', 'following', 'followers', 'communities'] as const;
  const anyRun = scopes.some((which) => !!ctl?.[which]?.running);

  if (!anyRun) {
    bar.setAttribute('hidden', '');
    try {
      const items = bar.querySelectorAll('[data-gbar-item]') as any;
      items.forEach((el: HTMLElement) => { el.style.display = 'none'; });
    } catch {}
    return;
  }

  bar.removeAttribute('hidden');

  let totalPct = 0;
  let totalCount = 0;

  const setItem = (which: typeof scopes[number], running: boolean) => {
    const item = bar.querySelector(`[data-gbar-item="${which}"]`) as HTMLElement | null;
    if (item) item.style.display = running ? '' : 'none';

    const prog = bar.querySelector(`[data-gbar-prog="${which}"]`) as HTMLElement | null;
    const pObj = ctl?.[which]?.progress;
    const pct = enrichProgPct(pObj);

    if (prog) {
      const txt = enrichProgSummary(pObj);
      prog.textContent = txt || t('report.enrichBar.running');
    }

    const fill = bar.querySelector(`[data-gbar-fill="${which}"]`) as HTMLElement | null;
    if (fill) fill.style.width = `${running ? Math.max(6, pct) : 0}%`;

    if (running) {
      totalPct += pct;
      totalCount += 1;
    }
  };

  for (const which of scopes) setItem(which, !!ctl?.[which]?.running);

  const allFill = bar.querySelector('[data-gbar-fill="all"]') as HTMLElement | null;
  if (allFill) {
    const avg = totalCount ? Math.round(totalPct / totalCount) : 0;
    allFill.style.width = `${Math.max(6, avg)}%`;
  }
}

