function positionTip(ev: PointerEvent) {
  if (!__vkxTipEl || !__vkxTipEl.classList.contains('show')) return;
  const pad = 14;
  const w = __vkxTipEl.offsetWidth || 240;
  const h = __vkxTipEl.offsetHeight || 80;
  let x = ev.clientX + 14;
  let y = ev.clientY + 14;
  if (x + w + pad > window.innerWidth) x = Math.max(pad, ev.clientX - w - 14);
  if (y + h + pad > window.innerHeight) y = Math.max(pad, ev.clientY - h - 14);
  __vkxTipEl.style.transform = `translate(${x}px, ${y}px)`;
}

