function stableHash(input: string): number {
  let h = 0;
  for (let i = 0; i < input.length; i++) {
    h = ((h << 5) - h) + input.charCodeAt(i);
    h |= 0;
  }
  return Math.abs(h);
}

function tsName() {
  const d = new Date();
  const pad = (n: number) => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}_${pad(d.getHours())}${pad(d.getMinutes())}${pad(d.getSeconds())}`;
}

function sanitizePathPart(v: any): string {
  return String(v ?? '')
    .replace(/[<>:]/g, '_')
    .replace(/["'`]/g, '')
    .replace(/[\/|?*]/g, '_')
    .replace(/[\x00-\x1F]/g, '_')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/ /g, '_')
    .slice(0, 96) || 'item';
}

function targetExportFolder(bundle: VkXtractBundle): string {
  const t = bundle?.target || ({} as any);
  const label = sanitizePathPart(t?.screenName || (t?.kind === 'group' ? 'group' : 'user'));
  const id = Number(t?.id);
  return `vkXtract/${label} - ${Number.isFinite(id) && id > 0 ? id : 'unknown'}`;
}

function snapshotRelativeOfflinePath(bundle: VkXtractBundle, localPath: string): string {
  const clean = String(localPath || '').trim().replace(/\\/g, '/');
  if (!clean) return '';
  const root = targetExportFolder(bundle);
  if (clean === root) return '..';
  if (clean.startsWith(root + '/')) return '../' + clean.slice(root.length + 1);
  return clean;
}

function snapshotPhotoOfflineLookup(bundle: VkXtractBundle): Record<string, { localRel: string; remoteUrl: string }> {
  const out: Record<string, { localRel: string; remoteUrl: string }> = {};
  const map = (bundle && typeof bundle.offlineMedia === 'object' && bundle.offlineMedia) ? bundle.offlineMedia : null;
  if (!map) return out;
  for (const [slot, rec] of Object.entries(map)) {
    if (!rec || typeof rec !== 'object') continue;
    const kind = String((rec as any).kind || '');
    if (kind !== 'photo') continue;
    const key = String((rec as any).key || (slot.startsWith('photo:') ? slot.slice(6) : '')).trim();
    const localRel = snapshotRelativeOfflinePath(bundle, String((rec as any).localPath || ''));
    const remoteUrl = String((rec as any).remoteUrl || '').trim();
    if (!key || !localRel || !remoteUrl) continue;
    out[key] = { localRel, remoteUrl };
  }
  return out;
}

