function inferExtFromMediaUrl(url: string, fallback = '.jpg'): string {
  const clean = String(url || '').split('#')[0].split('?')[0];
  const m = clean.match(/\.([a-zA-Z0-9]{2,5})$/);
  if (!m) return fallback;
  const ext = '.' + String(m[1] || '').toLowerCase();
  return ['.jpg', '.jpeg', '.png', '.webp', '.gif', '.bmp', '.tiff', '.avif'].includes(ext) ? ext : fallback;
}

function isCasePackageRemoteMediaUrlAllowed(url: string): boolean {
  const raw = String(url || '').trim();
  if (!raw) return false;
  if (!/^https?:\/\//i.test(raw)) return false;

  const clean = raw.toLowerCase();
  if (clean.includes('/assets/thumbnails/')) return false;

  return true;
}

function photoUrlForPackageJs(photo: any): string {
  const remoteUrl = String(bestPhotoUrlJs(photo) || '').trim();
  return isCasePackageRemoteMediaUrlAllowed(remoteUrl) ? remoteUrl : '';
}

function videoPosterUrlForPackageJs(v: any): string {
  const explicit = [v?.photo_320, v?.photo_160, v?.photo_130]
    .map((url: any) => String(url || '').trim())
    .find((url: string) => isCasePackageRemoteMediaUrlAllowed(url));
  if (explicit) return explicit;

  const imgs = Array.isArray(v?.image) ? v.image : [];
  if (imgs.length) {
    const usable = imgs
      .map((img: any) => ({
        width: Number(img?.width),
        height: Number(img?.height),
        url: String(img?.url || '').trim()
      }))
      .filter((img: any) => isCasePackageRemoteMediaUrlAllowed(img.url));

    if (usable.length) {
      const sorted = usable.slice().sort((a: any, b: any) => (Number(a?.width) * Number(a?.height)) - (Number(b?.width) * Number(b?.height)));
      const near = sorted.find((img: any) => Number(img?.width) >= 320) || sorted[sorted.length - 1];
      if (near?.url) return String(near.url);
    }
  }

  return '';
}

async function probeCasePackageRemoteMediaUrl(url: string): Promise<{ ok: boolean; error?: string }> {
  const clean = String(url || '').trim();
  if (!clean) return { ok: false, error: 'missing_remote_url' };

  const ctrl = new AbortController();
  const timer = window.setTimeout(() => ctrl.abort(), 12000);

  try {
    const res = await fetch(clean, {
      method: 'GET',
      cache: 'no-store',
      credentials: 'include',
      signal: ctrl.signal
    });

    try {
      await res.body?.cancel?.();
    } catch {}

    if (!res.ok) return { ok: false, error: `fetch ${res.status}` };
    return { ok: true };
  } catch (err: any) {
    return { ok: false, error: String(err?.message || err || 'fetch_failed') };
  } finally {
    window.clearTimeout(timer);
  }
}

async function filterCasePackageRemoteItemsForZip<T extends { remoteUrl: string; localPath: string }>(
  items: T[],
  kindLabel: string,
  progressBase: number,
  progressSpan: number
): Promise<{ kept: T[]; skipped: CasePackageSkippedAsset[] }> {
  const kept: T[] = [];
  const skipped: CasePackageSkippedAsset[] = [];
  const total = Math.max(items.length, 1);

  for (let i = 0; i < items.length; i++) {
    assertCasePackageExportNotCancelled();
    const item = items[i];
    const pct = progressBase + Math.round(((i + 1) / total) * progressSpan);
    setCasePackageBusy(true, `Checking packaged ${kindLabel} accessibility… (${i + 1}/${items.length})`, pct);

    const probe = await probeCasePackageRemoteMediaUrl(String(item.remoteUrl || '').trim());
    if (probe.ok) {
      kept.push(item);
    } else {
      skipped.push({
        path: String(item.localPath || '').trim(),
        remoteUrl: String(item.remoteUrl || '').trim(),
        error: String(probe.error || 'fetch_failed'),
        stage: 'preflight'
      });
    }
  }

  return { kept, skipped };
}

