function syncCasePackageActionButtons() {
  const cancelBtn = document.getElementById('vkxPkgCancel') as HTMLButtonElement | null;
  const confirmBtn = document.getElementById('vkxPkgConfirm') as HTMLButtonElement | null;
  const openBtn = document.getElementById('vkxPkgOpenFolder') as HTMLButtonElement | null;
  const done = !!(window as any).__vkxCasePackageDone;
  const mode = String((window as any).__vkxCasePackageCompletedMode || 'folder') === 'zip' ? 'zip' : 'folder';
  const busy = !!(window as any).__vkxCasePackageBusy;
  const busyMode = String((window as any).__vkxCasePackageBusyMode || '');
  const zipBusy = busy && busyMode === 'zip' && !!String((window as any).__vkxCasePackageZipExportId || '').trim();
  const folderBusy = busy && busyMode === 'folder';

  if (cancelBtn) {
    cancelBtn.hidden = done;
    cancelBtn.textContent = zipBusy ? t('report.common.cancelZipExport') : folderBusy ? t('report.common.cancelExport') : t('report.common.cancel');
  }
  if (confirmBtn) confirmBtn.hidden = done;
  if (openBtn) {
    openBtn.hidden = !done;
    openBtn.textContent = mode === 'zip' ? t('report.common.showExportedZipInDownloads') : t('report.common.openExportedPackageFolder');
  }
}

function resetCasePackageCompletion() {
  (window as any).__vkxCasePackageDone = false;
  (window as any).__vkxCasePackageFolderDownloadId = null;
  (window as any).__vkxCasePackageFolderPath = '';
  (window as any).__vkxCasePackageCompletedMode = 'folder';
  (window as any).__vkxCasePackageBusyMode = '';
  (window as any).__vkxCasePackageZipExportId = '';
  resetCasePackageFolderCancelState();
  syncCasePackageActionButtons();
}

function setCasePackageBusy(active: boolean, text = '', pct = 0) {
  const modal = document.getElementById('vkxPkgModal') as HTMLElement | null;
  const run = document.getElementById('vkxPkgRun') as HTMLElement | null;
  const txt = document.getElementById('vkxPkgRunText') as HTMLElement | null;
  const fill = document.getElementById('vkxPkgRunFill') as HTMLElement | null;
  if (!modal) return;

  (window as any).__vkxCasePackageBusy = !!active;

  modal.querySelectorAll('input, button, summary').forEach((el) => {
    const node = el as HTMLInputElement | HTMLButtonElement;
    const keepEnabled = !!active && node.id === 'vkxPkgCancel';

    if (active) {
      if (!node.hasAttribute('data-vkx-pkg-disabled')) {
        node.setAttribute('data-vkx-pkg-disabled', node.disabled ? '1' : '0');
      }
      node.disabled = keepEnabled ? false as any : true as any;
    } else {
      const was = node.getAttribute('data-vkx-pkg-disabled');
      node.disabled = was === '1';
      node.removeAttribute('data-vkx-pkg-disabled');
    }
  });

  if (run) run.hidden = !active && !text;
  if (txt) txt.textContent = text || t('report.common.idle');
  if (fill) fill.style.width = `${Math.max(0, Math.min(100, Number(pct || 0)))}%`;

  syncCasePackageActionButtons();
}

function setCasePackageCompleted(
  text = '',
  pct = 100,
  downloadId: number | null = null,
  pkgBase = '',
  outputMode: CasePackageOutputMode = 'folder'
) {
  (window as any).__vkxCasePackageDone = true;
  (window as any).__vkxCasePackageFolderDownloadId = Number.isFinite(Number(downloadId)) ? Number(downloadId) : null;
  (window as any).__vkxCasePackageFolderPath = String(pkgBase || '');
  (window as any).__vkxCasePackageCompletedMode = outputMode === 'zip' ? 'zip' : 'folder';
  (window as any).__vkxCasePackageBusyMode = '';
  (window as any).__vkxCasePackageZipExportId = '';
  setCasePackageBusy(false, text, pct);
  syncCasePackageActionButtons();
}

function openCasePackageFolderFromModal() {
  const downloadId = Number((window as any).__vkxCasePackageFolderDownloadId || 0);
  try {
    if (Number.isFinite(downloadId) && downloadId > 0) {
      chrome.downloads.show(downloadId);
      return;
    }
  } catch {}
  try {
    chrome.downloads.showDefaultFolder();
  } catch {}
}

async function pingCasePackageZipBroker(): Promise<any> {
  return await sendToBg({ type: 'VKX_ZIP_EXPORT_PING' });
}

async function startCasePackageZipBroker(plan: CasePackagePlan, exportId?: string): Promise<any> {
  const id = String(exportId || `zip_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`);
  (window as any).__vkxCasePackageZipExportId = id;
  return await sendToBg({ type: 'VKX_ZIP_EXPORT_START', exportId: id, plan });
}

async function cancelCasePackageZipBroker(exportId?: string): Promise<any> {
  const id = String(exportId || (window as any).__vkxCasePackageZipExportId || '').trim();
  if (!id) return { ok: false, error: 'zip_export_not_active' };
  return await sendToBg({ type: 'VKX_ZIP_EXPORT_CANCEL', exportId: id });
}

function bindCasePackageZipBridge() {
  if ((window as any).__vkxCasePackageZipBridgeBound) return;
  (window as any).__vkxCasePackageZipBridgeBound = true;

  chrome.runtime.onMessage.addListener((msg: any) => {
    const m = msg || {};
    const currentId = String((window as any).__vkxCasePackageZipExportId || '').trim();
    const msgId = String(m.exportId || '').trim();

    if (m.type === 'VKX_ZIP_EXPORT_PROGRESS') {
      if (currentId && msgId && currentId !== msgId) return false;

      const cancelRequested = !!(window as any).__vkxCasePackageCancelRequested;
      const text = String(m.text || t('report.common.preparingZipExport'));

      if (cancelRequested && text !== t('report.common.cancellingZipExport')) {
        return false;
      }

      (window as any).__vkxCasePackageZipLastProgress = m;
      setCasePackageBusy(true, text, Number(m.pct || 0));
      return false;
    }

    if (m.type === 'VKX_ZIP_EXPORT_DONE') {
      if (currentId && msgId && currentId !== msgId) return false;
      (window as any).__vkxCasePackageZipLastDone = m;
      (window as any).__vkxCasePackageZipExportId = '';
      (window as any).__vkxCasePackageBusyMode = '';

      const zipMsg = String(m.text || '').trim() || t('report.common.zipPackageSaved', { filename: String(m.filename || 'package.zip') });

      setCasePackageCompleted(
        zipMsg,
        100,
        Number(m.downloadId || 0) || null,
        String(m.filename || ''),
        'zip'
      );
      toast(zipMsg, 'ok');
      return false;
    }

    if (m.type === 'VKX_ZIP_EXPORT_ERROR') {
      if (currentId && msgId && currentId !== msgId) return false;
      (window as any).__vkxCasePackageZipLastError = m;

      const err = String(m.error || 'zip_export_failed');
      const cancelled = err === 'zip_export_cancelled';

      (window as any).__vkxCasePackageZipExportId = '';
      (window as any).__vkxCasePackageBusyMode = '';

      if (cancelled) {
        resetCasePackageCompletion();
        (window as any).__vkxCasePackageBusyMode = '';
        setCasePackageBusy(false, String(m.text || t('report.common.zipExportCancelled')), 0);
        return false;
      }

      handleCasePackageZipFallback(
        String(m.text || t('report.common.zipExportFailedRetryDetailed', { error: err })),
        bundleCache
      );
      toast(err, 'bad');
      return false;
    }

    return false;
  });
}

