function resetCasePackageFolderCancelState() {
  (window as any).__vkxCasePackageCancelRequested = false;
  (window as any).__vkxCasePackageDownloadIds = [];
}

function requestCasePackageFolderCancel() {
  (window as any).__vkxCasePackageCancelRequested = true;
  const ids = Array.isArray((window as any).__vkxCasePackageDownloadIds) ? (window as any).__vkxCasePackageDownloadIds.slice() : [];
  ids.forEach((id: any) => {
    const num = Number(id || 0);
    if (!Number.isFinite(num) || num <= 0) return;
    try { chrome.downloads.cancel(num); } catch {}
  });
}

function requestCasePackageExportCancel() {
  (window as any).__vkxCasePackageCancelRequested = true;
}

function assertCasePackageExportNotCancelled() {
  if ((window as any).__vkxCasePackageCancelRequested) {
    throw new Error('case_package_cancelled');
  }
}

function assertCasePackageFolderNotCancelled() {
  assertCasePackageExportNotCancelled();
}

async function executeCasePackageFolderPlan(
  plan: CasePackagePlan,
  onProgress?: (text: string, pct: number) => void
): Promise<number | null> {
  let revealId: number | null = null;
  resetCasePackageFolderCancelState();

  for (const entry of plan.entries) {
    assertCasePackageFolderNotCancelled();

    if (onProgress && entry.progressText) {
      onProgress(String(entry.progressText || ''), Number(entry.progressPct || 0));
    }

    let downloadId: number | null = null;

    if (entry.sourceKind === 'text') {
      downloadId = await download(
        entry.path,
        new Blob([String(entry.text || '')], { type: String(entry.mime || 'text/plain') }),
        { saveAs: false }
      );
    } else if (entry.sourceKind === 'json') {
      downloadId = await download(
        entry.path,
        new Blob([JSON.stringify(entry.jsonValue ?? null, null, 2)], { type: String(entry.mime || 'application/json') }),
        { saveAs: false }
      );
    } else if (entry.sourceKind === 'blob') {
      downloadId = await download(
        entry.path,
        entry.blob || new Blob([], { type: String(entry.mime || 'application/octet-stream') }),
        { saveAs: false }
      );
    } else if (entry.sourceKind === 'remote-url') {
      const remoteUrl = String(entry.remoteUrl || '').trim();
      if (!remoteUrl) throw new Error(`case_package_failed: missing remote URL for ${entry.path}`);
      downloadId = await downloadRemoteToFile(remoteUrl, entry.path, { saveAs: false });
    }

    if (Number.isFinite(Number(downloadId)) && Number(downloadId) > 0) {
      const arr = Array.isArray((window as any).__vkxCasePackageDownloadIds) ? (window as any).__vkxCasePackageDownloadIds : [];
      arr.push(Number(downloadId));
      (window as any).__vkxCasePackageDownloadIds = arr;
    }

    assertCasePackageFolderNotCancelled();

    if (entry.path === plan.revealPath) {
      revealId = downloadId;
    }
  }

  return revealId;
}

async function blobToDataUrl(blob: Blob): Promise<string> {
  return await new Promise((resolve, reject) => {
    const r = new FileReader();
    r.onerror = () => reject(new Error('Failed to read blob.'));
    r.onload = () => resolve(String(r.result || ''));
    r.readAsDataURL(blob);
  });
}

function getActivePageUrl(bundle: VkXtractBundle): string {
  return String(bundle.lastPageUrl || bundle.target?.url || '');
}

let bundleCache: VkXtractBundle | null = null;
let enrichTimers: Record<string, number> = {};

function wireImgFallbacks() {
  const imgs = document.querySelectorAll('img[data-fallback="no-thumb"]') as NodeListOf<HTMLImageElement>;
  imgs.forEach((img) => {
    if ((img as any).__vkxBound) return;
    (img as any).__vkxBound = true;
    img.addEventListener('error', () => {
      const wrap = (img.closest('.gridThumb') as HTMLElement | null) || (img.parentElement as HTMLElement | null);
      if (wrap) wrap.innerHTML = `<div class="thumbFallback">${escH(t('report.common.noThumbnail'))}</div>`;
    }, { once: true });
  });
}

type UIState = {
  tabInputId?: string;
  scrollY?: number;
  miniChecked?: Record<string, string>;
  openLeader?: Array<{ scope: 'photo' | 'video'; userId: number }>;
  openHotspots?: Array<{ scope: 'photo' | 'video'; key: string }>;
  lightbox?: { open: boolean; src?: string };
  openMediaDrops?: string[];
  openCardDetails?: string[];
  openWideCardDetails?: string[];
};

function captureUIState(): UIState {
  const checked = document.querySelector('input.tabRadio[name="vkxTab"]:checked') as HTMLInputElement | null;

  const miniChecked: Record<string, string> = {};
  const minis = Array.from(document.querySelectorAll('input[type="radio"][name^="mini-"]')) as HTMLInputElement[];
  for (const r of minis) {
    if (!r.checked) continue;
    const name = String(r.name || '');
    if (name) miniChecked[name] = r.id;
  }

  const openLeader: Array<{ scope: 'photo' | 'video'; userId: number }> = [];
  const ld = Array.from(document.querySelectorAll('.leaderDetail.open')) as HTMLElement[];
  for (const el of ld) {
    const scope = String(el.getAttribute('data-scope') || '') as any;
    const userId = Number(el.getAttribute('data-user-id'));
    if ((scope === 'photo' || scope === 'video') && Number.isFinite(userId)) openLeader.push({ scope, userId });
  }

  const openHotspots: Array<{ scope: 'photo' | 'video'; key: string }> = [];
  const hd = Array.from(document.querySelectorAll('.hotspotDetail.open, .hotspotDetailWide.open')) as HTMLElement[];
  for (const el of hd) {
    const scope = String(el.getAttribute('data-hotspot-detail') || '') as any;
    const key = String(el.getAttribute('data-hotspot-key') || '');
    if ((scope === 'photo' || scope === 'video') && key) openHotspots.push({ scope, key });
  }

  const lb = document.getElementById('vkxLightbox');
  const im = document.getElementById('vkxLightboxImg') as HTMLImageElement | null;
  const lightbox = lb ? { open: lb.classList.contains('open'), src: im?.src || '' } : { open: false, src: '' };

  const openMediaDrops = Array.from(document.querySelectorAll('.mediaDrop.open[data-media-drop], .vkxWideMedia[data-media-drop]'))
    .map((el) => String((el as HTMLElement).getAttribute('data-media-drop') || ''))
    .filter(Boolean);

  const openCardDetails = Array.from(document.querySelectorAll('.mediaDrop.open[data-card-detail]'))
    .map((el) => String((el as HTMLElement).getAttribute('data-card-detail') || ''))
    .filter(Boolean);

  const openWideCardDetails = Array.from(document.querySelectorAll('.vkxWideDrop[data-wide-drop]'))
    .map((el) => String((el as HTMLElement).getAttribute('data-wide-drop') || ''))
    .filter(Boolean);

  return {
    tabInputId: checked?.id || undefined,
    scrollY: window.scrollY,
    miniChecked,
    openLeader,
    openHotspots,
    lightbox,
    openMediaDrops,
    openCardDetails,
    openWideCardDetails
  };
}

function restoreUIState(state?: UIState) {
  if (!state) return;

  if (state.tabInputId) {
    const r = document.getElementById(state.tabInputId) as HTMLInputElement | null;
    if (r) r.checked = true;
  }

  if (state.miniChecked) {
    for (const [name, id] of Object.entries(state.miniChecked)) {
      const r = document.getElementById(id) as HTMLInputElement | null;
      if (r && r.name === name) r.checked = true;
    }
  }

  requestAnimationFrame(() => {
    for (const it of state.openLeader || []) {
      const detail = document.querySelector(`.leaderDetail[data-scope="${it.scope}"][data-user-id="${it.userId}"]`) as HTMLElement | null;
      if (detail) {
        detail.classList.add('open');
        if (!detail.innerHTML.trim()) detail.innerHTML = buildLeaderDetail(it.scope, it.userId);
      }
    }

    for (const it of state.openHotspots || []) {
      const card = document.querySelector(`.hotspotCard[data-scope="${it.scope}"][data-hotspot-key="${CSS.escape(it.key)}"]`) as HTMLElement | null;
      if (card) {
        ensureHotspotWideDrop(card, it.scope, it.key, { scroll: false });
      }
    }

    const lb = document.getElementById('vkxLightbox') as HTMLElement | null;
    const im = document.getElementById('vkxLightboxImg') as HTMLImageElement | null;
    if (lb && im && state.lightbox?.open && state.lightbox?.src) {
      im.src = state.lightbox.src;
      lb.classList.add('open');
      lb.setAttribute('aria-hidden', 'false');
    }

    // Restore open media dropdowns (photos/videos/clips)
    for (const k of (state.openMediaDrops || [])) {
      try { openMediaDrop(k); } catch {}
    }

    // Restore open entity detail dropdowns (user/group cards)
    for (const k of (state.openCardDetails || [])) {
      try { openCardDetail(k); } catch {}
    }

    for (const k of (state.openWideCardDetails || [])) {
      try { openWideCardDetail(k); } catch {}
    }

    // Restore scroll LAST (avoids jumps caused by re-opening dropdowns altering layout above the viewport)
    if (typeof state.scrollY === 'number' && Number.isFinite(state.scrollY)) {
      window.scrollTo({ top: state.scrollY });
    }
  });
}

function escMini(s: any): string {
  const str = String(s ?? '');
  return str.replace(/[&<>"']/g, (ch) => {
    if (ch === '&') return '&amp;';
    if (ch === '<') return '&lt;';
    if (ch === '>') return '&gt;';
    if (ch === '"') return '&quot;';
    return '&#39;';
  });
}

function cssEscAttr(v: string): string {
  try { return (CSS as any).escape(String(v)); } catch {
    return String(v).replace(/[^a-zA-Z0-9_-]/g, (c) => `\\${c.charCodeAt(0).toString(16)} `);
  }
}

function closeNearestDrop(from: HTMLElement) {
  const wideMedia = from.closest('.vkxWideMedia') as HTMLElement | null;
  if (wideMedia) { wideMedia.remove(); return; }

  const wideRow = from.closest('.vkxWideDropRow') as HTMLElement | null;
  if (wideRow) { closeWideDropRow(); return; }

  const wide = from.closest('.vkxWideDrop') as HTMLElement | null;
  if (wide) { wide.remove(); resetCardExpandButtons(); return; }

  const drop = from.closest('.mediaDrop') as HTMLElement | null;
  if (!drop) return;
  drop.classList.remove('open');
}

function openMediaDrop(dropKey: string) {
  const key = String(dropKey || '');
  if (!key) return;

  let drop = document.querySelector(`.mediaDrop[data-media-drop="${cssEscAttr(key)}"]`) as HTMLElement | null;
  if (!drop) {
    const btn = document.querySelector(`button[data-media-toggle="1"][data-media-drop="${cssEscAttr(key)}"]`) as HTMLButtonElement | null;
    if (btn && String(btn.getAttribute('data-media-wide') || '') === '1') {
      drop = ensureWideMediaDrop(btn, key, { scroll: false, forceOpen: true });
    }
  }
  if (!drop) return;

  drop.classList.add('open');
  if (!drop.innerHTML.trim()) {
    const btn = document.querySelector(`button[data-media-toggle="1"][data-media-drop="${cssEscAttr(key)}"]`) as HTMLButtonElement | null;
    if (btn) {
      if (String(btn.getAttribute('data-media-wide') || '') === '1') fillWideMediaDrop(btn, drop);
      else fillMediaDrop(btn, drop);
    }
  }
}

function openCardDetail(detailId: string) {
  const id = String(detailId || '');
  if (!id) return;
  const drop = document.querySelector(`.mediaDrop[data-card-detail="${cssEscAttr(id)}"]`) as HTMLElement | null;
  if (!drop) return;
  drop.classList.add('open');
  if (!drop.innerHTML.trim()) fillCardDetail(id, drop);
}

function openWideCardDetail(detailId: string) {
  const id = String(detailId || '');
  if (!id) return;

  if (id.startsWith('observed:')) {
    const actorId = Number(id.split(':', 2)[1]);
    const card = document.querySelector(`.gridCard[data-card-key="${cssEscAttr(id)}"]`) as HTMLElement | null;
    if (!card || !bundleCache || !Number.isFinite(actorId) || actorId === 0) return;
    const resp = getWallSnapshot(bundleCache);
    if (!resp) return;
    ensureObservedWideDrop(card, actorId, bundleCache, resp, { scroll: false });
    return;
  }

  const card = document.querySelector(`.gridCard[data-card-key="${cssEscAttr(id)}"]`) as HTMLElement | null;
  if (!card) return;
  ensureWideDrop(card, id, { scroll: false });
}

function resetCardExpandButtons() {
  try {
    for (const b of Array.from(document.querySelectorAll('button[data-card-expand].is-open'))) {
      const btn = b as HTMLButtonElement;
      btn.classList.remove('is-open');
      btn.textContent = '▾';
    }
  } catch {}
}

function closeWideDropRow() {
  try {
    const row = document.querySelector('.vkxWideDropRow') as HTMLElement | null;
    if (row) row.remove();
  } catch {}
  resetCardExpandButtons();
}

function ensureWideDrop(card: HTMLElement, detailId: string, opts?: { scroll?: boolean }) {
  const id = String(detailId || '');
  if (!id) return;

  const grid = card.closest('.grid') as HTMLElement | null;
  if (!grid) return;

  const existing = grid.querySelector('.vkxWideDropRow') as HTMLElement | null;
  const existingId = existing ? String(existing.getAttribute('data-wide-drop-id') || '') : '';

  // Toggle close if the same card is opened again
  if (existing && existingId === id) {
    closeWideDropRow();
    return;
  }
  // Close any other open drop row
  closeWideDropRow();

  const row = document.createElement('div');
  row.className = 'vkxWideDrop vkxWideDropRow';
  row.setAttribute('data-wide-drop-id', id);
  row.innerHTML = `
    <div class="vkxWideDropPointer" aria-hidden="true"><span></span></div>
    <div class="vkxWideDropInner"></div>
  `;

  // Full-width grid row
  (row.style as any).gridColumn = '1 / -1';

  // Insert after the end of the VISUAL row containing the clicked card (robust for responsive/auto-fill grids).
  const cards = Array.from(grid.querySelectorAll(':scope > .gridCard')) as HTMLElement[];
  let insertAfter = card;

  try {
    const y = card.getBoundingClientRect().top;
    const sameRow = cards.filter((c) => Math.abs(c.getBoundingClientRect().top - y) < 6);
    if (sameRow.length) insertAfter = sameRow[sameRow.length - 1];
  } catch {
    insertAfter = card;
  }

  grid.insertBefore(row, insertAfter.nextSibling);

  // Align pointer to the clicked card center
  try {
    const gridRect = grid.getBoundingClientRect();
    const cardRect = card.getBoundingClientRect();
    const cx = (cardRect.left + cardRect.width / 2) - gridRect.left;
    row.style.setProperty('--vkx-drop-pointer-left', `${cx}px`);
  } catch {}

  // Mark the arrow as open
  try {
    const exp = card.querySelector(`button[data-card-expand="${cssEscAttr(id)}"]`) as HTMLButtonElement | null;
    if (exp) {
      exp.classList.add('is-open');
      exp.textContent = '▴';
    }
  } catch {}

  // Fill content (uses your existing enriched detail renderer)
  const inner = row.querySelector('.vkxWideDropInner') as HTMLElement | null;
  if (inner) fillCardDetail(id, inner);

  if (opts?.scroll !== false) {
    try { row.scrollIntoView({ block: 'nearest', behavior: 'smooth' }); } catch {}
  }
}

function closeHotspotWideDrop(grid: HTMLElement) {
  try {
    const ex = grid.querySelector('.vkxHotspotDropRow') as HTMLElement | null;
    if (ex) ex.remove();
  } catch {}
}

function ensureHotspotWideDrop(card: HTMLElement, scope: 'photo' | 'video', key: string, opts?: { scroll?: boolean }) {
  const k = String(key || '');
  if (!k) return;

  const grid = card.closest('.hotspotGrid') as HTMLElement | null;
  if (!grid) return;

  const existing = grid.querySelector('.vkxHotspotDropRow') as HTMLElement | null;
  const exScope = existing ? String(existing.getAttribute('data-hotspot-detail') || '') : '';
  const exKey = existing ? String(existing.getAttribute('data-hotspot-key') || '') : '';

  // Toggle close if same card re-opened
  if (existing && exScope === scope && exKey === k) {
    existing.remove();
    return;
  }

  closeHotspotWideDrop(grid);

  const row = document.createElement('div');
  row.className = 'vkxWideDrop vkxWideDropRow vkxHotspotDropRow hotspotDetailWide open';
  row.setAttribute('data-hotspot-detail', scope);
  row.setAttribute('data-hotspot-key', k);
  row.innerHTML = `
    <div class="vkxWideDropPointer" aria-hidden="true"><span></span></div>
    <div class="vkxWideDropInner"></div>
  `;

  // Full-width grid item
  (row.style as any).gridColumn = '1 / -1';

  // Insert after end of VISUAL row that contains the clicked hotspot card
  const cards = Array.from(grid.querySelectorAll(':scope > .hotspotCard')) as HTMLElement[];
  let insertAfter = card;
  try {
    const y = card.getBoundingClientRect().top;
    const sameRow = cards.filter((c) => Math.abs(c.getBoundingClientRect().top - y) < 6);
    if (sameRow.length) insertAfter = sameRow[sameRow.length - 1];
  } catch {}

  grid.insertBefore(row, insertAfter.nextSibling);

  // Pointer position = clicked card center (relative to grid)
  try {
    const gridRect = grid.getBoundingClientRect();
    const cardRect = card.getBoundingClientRect();
    const cx = (cardRect.left + cardRect.width / 2) - gridRect.left;
    row.style.setProperty('--vkx-drop-pointer-left', `${cx}px`);
  } catch {}

  // Fill content
  const inner = row.querySelector('.vkxWideDropInner') as HTMLElement | null;
  if (inner) inner.innerHTML = buildHotspotDetail(scope, k, { compact: true });

  if (opts?.scroll !== false) {
    try { row.scrollIntoView({ block: 'nearest', behavior: 'smooth' }); } catch {}
  }
}

function ensureZoomState(wrap: HTMLElement) {
  const cur = Number(wrap.getAttribute('data-zoom-scale') || '1');
  if (!Number.isFinite(cur) || cur <= 0) wrap.setAttribute('data-zoom-scale', '1');

  const panX = Number(wrap.getAttribute('data-pan-x') || '0');
  const panY = Number(wrap.getAttribute('data-pan-y') || '0');
  if (!Number.isFinite(panX)) wrap.setAttribute('data-pan-x', '0');
  if (!Number.isFinite(panY)) wrap.setAttribute('data-pan-y', '0');
}

function applyZoomTransform(wrap: HTMLElement) {
  ensureZoomState(wrap);

  const s = Math.max(1, Math.min(6, Number(wrap.getAttribute('data-zoom-scale') || '1')));
  const panX = Number(wrap.getAttribute('data-pan-x') || '0') || 0;
  const panY = Number(wrap.getAttribute('data-pan-y') || '0') || 0;
  const img = wrap.querySelector('img') as HTMLImageElement | null;

  if (img) {
    img.style.transform = `translate(${panX}px, ${panY}px) scale(${s})`;
  }

  wrap.classList.toggle('is-pan-ready', s > 1.001);
  if (s <= 1.001) {
    wrap.classList.remove('is-dragging');
  }

  const host = (wrap.closest('.mediaDrop') as HTMLElement | null) || wrap;
  const lab = host.querySelector('[data-media-zoom-val="1"]') as HTMLElement | null;
  if (lab) lab.textContent = `${Math.round(s * 100)}%`;
}

function setZoom(wrap: HTMLElement, scale: number) {
  const s = Math.max(1, Math.min(6, scale));
  wrap.setAttribute('data-zoom-scale', String(s));
  if (s <= 1.001) {
    wrap.setAttribute('data-pan-x', '0');
    wrap.setAttribute('data-pan-y', '0');
  }
  applyZoomTransform(wrap);
}

function fillMediaDrop(btn: HTMLButtonElement, drop: HTMLElement) {
  const kind = String(btn.getAttribute('data-media-kind') || '');
  const src = String(btn.getAttribute('data-media-src') || '');
  const hq = String(btn.getAttribute('data-media-hq') || src);
  const iframe = String(btn.getAttribute('data-media-iframe') || '');
  const dropKey = String(btn.getAttribute('data-media-drop') || '');

  if (kind === 'photo') {
    const top = `
      <div class="mediaViewerTop">
        <span class="muted">${escMini(t('report.common.mousewheelToZoom'))}</span>
        <span style="flex:1"></span>
        ${hq ? `<a class="gridLinkBtn" href="${escMini(hq)}" target="_blank" rel="noreferrer">${escMini(t('report.common.openExternal'))}</a>` : ''}
        <button class="gridLinkBtn" type="button" data-media-zoom-reset="1">${escMini(t('report.common.resetZoom'))}</button>
        <button class="gridLinkBtn" type="button" data-media-close="1">${escMini(t('report.common.close'))}</button>
      </div>`;

    const img = hq
      ? `<div class="mediaZoomWrap" data-media-zoom="1"><img class="mediaZoomImg" src="${escMini(hq)}" alt="" referrerpolicy="no-referrer" loading="lazy" /></div>`
      : `<div class="empty">${escMini(t('report.common.noImageUrlAvailable'))}</div>`;

    drop.innerHTML = `<div class="mediaViewer">${top}${img}</div>`;
    const wrap = drop.querySelector('.mediaZoomWrap') as HTMLElement | null;
    if (wrap) {
      ensureZoomState(wrap);
      setZoom(wrap, 1);
    }
    return;
  }

  // video / clip
  const keyPart = dropKey.includes(':') ? dropKey.split(':', 2)[1] : '';
  const link = keyPart ? `https://vk.com/video${keyPart}` : '';
  const ar = (kind === 'clip') ? '9 / 16' : '16 / 9';

  const top = `
    <div class="mediaViewerTop">
      ${link ? `<a class="gridLinkBtn" href="${escMini(link)}" target="_blank" rel="noreferrer">${escMini(t('report.common.openExternal'))}</a>` : ''}
      <span style="flex:1"></span>
      <button class="gridLinkBtn" type="button" data-media-close="1">${escMini(t('report.common.close'))}</button>
    </div>`;

  const body = iframe
    ? `<div class="mediaIframeWrap" style="aspect-ratio:${ar};"><iframe src="${escMini(iframe)}" allow="autoplay; encrypted-media; fullscreen; picture-in-picture" allowfullscreen loading="lazy" referrerpolicy="no-referrer" style="width:100%;height:100%;border:0;border-radius:12px;"></iframe></div>`
    : `<div class="empty">${escMini(t('report.common.noEmbeddablePlayerReturned'))}</div>`;

  drop.innerHTML = `<div class="mediaViewer">${top}${body}</div>`;
}

function mediaKeyFromDrop(dropKey: string): string {
  const s = String(dropKey || '');
  if (!s) return '';
  const parts = s.split(':', 2);
  return parts.length === 2 ? parts[1] : s;
}

function ensureWideMediaDrop(btn: HTMLButtonElement, dropKey: string, opts?: { scroll?: boolean; toggle?: boolean; forceOpen?: boolean }): HTMLElement | null {
  const key = String(dropKey || '');
  if (!key) return null;

  const card = btn.closest('.gridCard') as HTMLElement | null;
  if (!card) return null;
  const grid = card.parentElement as HTMLElement | null;
  if (!grid || !grid.classList.contains('grid')) return null;

  const existing = grid.querySelector(`.vkxWideMedia[data-media-drop="${cssEscAttr(key)}"]`) as HTMLElement | null;
  if (existing && opts?.toggle) {
    existing.remove();
    return null;
  }

  // Only one wide-media drop per grid
  for (const el of Array.from(grid.querySelectorAll('.vkxWideMedia[data-media-drop]'))) {
    (el as HTMLElement).remove();
  }

  const host = document.createElement('div');
  host.className = 'vkxWideMedia mediaDrop';
  host.setAttribute('data-media-drop', key);
  host.style.gridColumn = '1 / -1';

  const after = card.nextSibling;
  if (after) grid.insertBefore(host, after);
  else grid.appendChild(host);

  if (opts?.forceOpen !== false) host.classList.add('open');
  fillWideMediaDrop(btn, host);

  if (opts?.scroll !== false) {
    try { host.scrollIntoView({ block: 'nearest', behavior: 'smooth' }); } catch {}
  }

  return host;
}

function buildWideMediaEngagementBlock(scope: 'photo' | 'video', mediaKey: string): string {
  const b = bundleCache;
  if (!b) return `<div class="empty">${escHtml(t('report.common.noBundleLoaded'))}</div>`;

  const enrich = getEnrich(b, scope);
  if (!enrich) {
    return `<div class="empty">${escHtml(t('report.common.noEnrichmentDataYetForScope'))}</div>`;
  }

  const mediaObj = scope === 'photo' ? enrich?.media?.photos : enrich?.media?.videos;
  const rec = (mediaObj && typeof mediaObj === 'object') ? (mediaObj as any)[mediaKey] : null;
  if (!rec) {
    return `<div class="empty">${escHtml(t('report.common.notEnrichedForThisItemYet'))}</div>`;
  }

  const likesIds = Array.isArray(rec?.likes_ids) ? rec.likes_ids : [];
  const copiesIds = Array.isArray(rec?.copies_ids) ? rec.copies_ids : [];
  const commentItems = Array.isArray(rec?.comment_items) ? rec.comment_items : [];
  const uniq = new Set<number>();
  for (const x of likesIds) { const n = Number(x); if (Number.isFinite(n) && n) uniq.add(n); }
  for (const x of copiesIds) { const n = Number(x); if (Number.isFinite(n) && n) uniq.add(n); }
  for (const c of commentItems) { const n = Number(c?.from_id); if (Number.isFinite(n) && n) uniq.add(n); }

  const summary = `<div class="muted" style="margin-top:6px;">${escMini(t('report.common.capturedEngagementSummary', {
    likes: String(likesIds.length),
    reposts: String(copiesIds.length),
    comments: String(commentItems.length),
    unique: String(uniq.size)
  }))}</div>`;
  const detail = buildHotspotDetail(scope, mediaKey, { compact: true });
  return summary + `<div style="margin-top:10px;">${detail}</div>`;
}

function fillWideMediaDrop(btn: HTMLButtonElement, drop: HTMLElement) {
  const kind = String(btn.getAttribute('data-media-kind') || '');
  const scope: 'photo' | 'video' = (kind === 'photo') ? 'photo' : 'video';

  const src = String(btn.getAttribute('data-media-src') || '');
  const hq = String(btn.getAttribute('data-media-hq') || src);
  const iframe = String(btn.getAttribute('data-media-iframe') || '');
  const dropKey = String(btn.getAttribute('data-media-drop') || '');
  const mediaKey = String(btn.getAttribute('data-media-key') || '') || mediaKeyFromDrop(dropKey);
  const title = String(btn.getAttribute('data-media-title') || (scope === 'photo' ? `photo${mediaKey}` : `video${mediaKey}`));

  const b = bundleCache;
  const base = b ? (getMediaMap(b, scope).get(mediaKey) || null) : null;

  const link = scope === 'photo'
    ? `https://vk.com/photo${mediaKey}`
    : `https://vk.com/video${mediaKey}${base?.access_key ? `_${String(base.access_key)}` : ''}`;

  const isEnriched = (() => {
    if (!b) return false;
    const e = getEnrich(b, scope);
    const mediaObj = scope === 'photo' ? e?.media?.photos : e?.media?.videos;
    const rec = (mediaObj && typeof mediaObj === 'object') ? (mediaObj as any)[mediaKey] : null;
    return !!rec;
  })();
  const enrichIcon = isEnriched ? '↻' : '⚡';
  const enrichText = isEnriched ? t('report.common.reEnrichShort') : t('report.common.enrichShort');

  const leftTop = `
    <div class="mediaViewerTop" style="margin-bottom:10px;">
      <div style="min-width:0;">
        <div style="font-weight:900; font-size:13px;">${escMini(title)}</div>
        <div class="muted">${escMini(scope === 'photo' ? `photo${mediaKey}` : `video${mediaKey}`)}</div>
      </div>
      <span style="flex:1"></span>
      <a class="gridLinkBtn" href="${escMini(link)}" target="_blank" rel="noreferrer">↗</a>
      <button class="gridLinkBtn" type="button" data-enrich-media="${escMini(scope)}" data-media-key="${escMini(mediaKey)}"><span class="gridLinkIcon">${enrichIcon}</span> ${enrichText}</button>
      <button class="gridLinkBtn" type="button" data-media-close="1">${escMini(t('report.common.close'))}</button>
    </div>`;
  const left = leftTop + buildWideMediaEngagementBlock(scope, mediaKey);

  let right = '';
  if (kind === 'photo') {
      const controls = `
      <div class="vkxMediaControls">
        <div class="hint">${escMini(t('report.common.zoom'))}</div>
        <div style="display:flex; gap:8px; align-items:center;">
          <button class="vkxIconBtn" type="button" title="${escMini(t('report.common.zoomOut'))}" data-media-zoom-out="1">−</button>
          <div class="vkxZoomVal" data-media-zoom-val="1">100%</div>
          <button class="vkxIconBtn" type="button" title="${escMini(t('report.common.zoomIn'))}" data-media-zoom-in="1">+</button>
          <button class="gridLinkBtn" type="button" data-media-zoom-reset="1">${escMini(t('report.common.reset'))}</button>
        </div>
      </div>`;

    const body = hq
      ? `<div class="mediaZoomWrap" data-media-zoom="1"><img class="mediaZoomImg" src="${escMini(hq)}" alt="" referrerpolicy="no-referrer" loading="lazy" /></div>`
      : `<div class="empty">${escMini(t('report.common.noImageUrlAvailable'))}</div>`;

    right = controls + body;
  } else {
    const ar = (kind === 'clip') ? '9 / 16' : '16 / 9';
    const controls = `
      <div class="vkxMediaControls">
        <div class="hint">${escMini(t('report.common.player'))}</div>
        <div style="display:flex; gap:8px; align-items:center;">
          <a class="gridLinkBtn" href="${escMini(link)}" target="_blank" rel="noreferrer">${escMini(t('report.common.openExternal'))}</a>
        </div>
      </div>`;

    const body = iframe
      ? `<div class="mediaIframeWrap" style="aspect-ratio:${ar};"><iframe src="${escMini(iframe)}" allow="autoplay; encrypted-media; fullscreen; picture-in-picture" allowfullscreen loading="lazy" referrerpolicy="no-referrer" style="width:100%;height:100%;border:0;border-radius:12px;"></iframe></div>`
      : `<div class="empty">${escMini(t('report.common.noEmbeddablePlayerReturned'))}</div>`;

    right = controls + body;
  }

  drop.innerHTML = `<div class="vkxWideMediaGrid"><div class="vkxMediaSide">${left}</div><div class="vkxMediaMain">${right}</div></div>`;

  const wrap = drop.querySelector('.mediaZoomWrap') as HTMLElement | null;
  if (wrap) {
    ensureZoomState(wrap);
    setZoom(wrap, 1);
  }
}

function findResolvedUser(bundle: VkXtractBundle, id: number): any | null {
  const abs = Math.abs(id);

  // Primary: full resolve pack (vkx.users.resolve)
  const glob = getResolvedUsersGlobal(bundle);
  for (const u of glob) {
    const uid = Number(u?.id);
    if (uid === id || uid === abs) return u;
  }

  // Media enrichment resolved users (photo/video) should also hydrate user detail lightboxes.
  for (const scope of ['photo', 'video'] as const) {
    const enrich = getEnrich(bundle, scope);
    const arr = Array.isArray(enrich?.resolved_users) ? enrich.resolved_users as any[] : [];
    for (const u of arr) {
      const uid = Number(u?.id);
      if (uid === id || uid === abs) return u;
    }
  }

  // Target profile (users.get) fallback: lets comment-click on the target user open a rich lightbox
  if ((bundle.target as any)?.kind === 'user') {
    const tid = Number((bundle.target as any)?.id);
    if (tid === abs) {
      const profRun = latestOkRun(bundle, (x) => x.action === 'users.get');
      const profArr = (profRun && Array.isArray((profRun as any).response)) ? (profRun as any).response as any[] : [];
      const prof = profArr.find((u: any) => Number(u?.id) === abs) || profArr[0];
      if (prof && Number(prof?.id) === abs) return prof;
    }
  }

  // Group contacts: users.get_group_contacts returns a plain users.get array
  const gcRun = latestOkRun(bundle, (x) => x.action === 'users.get_group_contacts');
  const gcArr = (gcRun && Array.isArray((gcRun as any).response)) ? (gcRun as any).response as any[] : [];
  for (const u of gcArr) {
    const uid = Number(u?.id);
    if (uid === id || uid === abs) return u;
  }

  // Friends/members meta map (light cards)
  try {
    const pack = getFriendPackH(bundle);
    if (pack.metaMap.has(abs)) return pack.metaMap.get(abs);
  } catch {}

  return null;
}

function findResolvedGroup(bundle: VkXtractBundle, id: number): any | null {
  const gid = Math.abs(id);

  const glob = getResolvedGroupsGlobal(bundle);
  for (const g of glob) {
    const id2 = Number(g?.id);
    if (id2 === gid) return g;
  }

  // Target profile (groups.getById) fallback: lets the target group render with real name/photo
  if ((bundle.target as any)?.kind === 'group') {
    const tid = Number((bundle.target as any)?.id);
    if (tid === gid) {
      const profRun = latestOkRun(bundle, (x) => x.action === 'groups.getById');
      const profResp: any = profRun?.response;
      const profArr = Array.isArray(profResp)
        ? profResp
        : (Array.isArray(profResp?.groups) ? profResp.groups : []);
      const prof = profArr.find((g: any) => Number(g?.id) === gid) || profArr[0];
      if (prof && Number(prof?.id) === gid) return prof;
    }
  }

  return null;
}

