function findObservedActorForDetail(bundle: VkXtractBundle, actorId: number): any | null {
  const resp = getWallSnapshot(bundle);
  if (!resp) return null;
  const merged = observedMerged(bundle, resp);
  return merged.actors.find((x: any) => Number(x?.id) === Number(actorId)) || null;
}

function observedEvidenceForDetail(bundle: VkXtractBundle, actorId: number, source: 'wall' | 'photo' | 'video'): any[] {
  const actor = findObservedActorForDetail(bundle, actorId);
  if (!actor) return [];
  return observedEvidenceRows(actor, source).slice(0, 120);
}

function buildInteractionEvidencePanel(bundle: VkXtractBundle, actorId: number, source: 'wall' | 'photo' | 'video', title: string): string {
  const rows = observedEvidenceForDetail(bundle, actorId, source);
  if (!rows.length) return '';

  const list = rows.map((ev: any) => {
    const pid = Number(ev?.post_id ?? 0) || 0;
    const mediaKey = String(ev?.media_key || '');
    const commentId = Number(ev?.comment_id ?? 0) || 0;
    const action = String(ev?.action || 'interaction');
    const ts = Number(ev?.ts ?? 0);
    const when = ts > 0 ? wallFmtTs(ts) : '—';
    const excerpt = String(ev?.excerpt || '').replace(/\s+/g, ' ').trim();
    const excerptLine = excerpt ? (excerpt.length > 180 ? `${excerpt.slice(0, 180).trim()}…` : excerpt) : '';
    const target = source === 'wall'
      ? t('report.common.wallPostLabel', { id: String(pid) })
      : `${source === 'photo' ? t('report.common.photoShort') : t('report.common.videoShort')} ${mediaKey || `#${Number(ev?.item_id ?? 0) || 0}`}`;

    return `
      <div class="listRow" style="align-items:flex-start;">
        <div style="min-width:0;flex:1;">
          <div class="listTitle">${escMini(target)} • ${escMini(action)}</div>
          <div class="listMeta">${escMini(when)}${excerptLine ? ` • ${escMini(excerptLine)}` : ''}${commentId ? ` • ${escMini(t('report.common.commentLabel'))} #${escMini(String(commentId))}` : ''}</div>
        </div>
        <button class="gridLinkBtn" type="button"
          data-activity-jump="1"
          data-activity-source="${escMini(source)}"
          data-post-id="${escMini(String(pid))}"
          data-comment-id="${escMini(String(commentId))}"
          data-media-key="${escMini(mediaKey)}">${escMini(t('report.common.openItem'))}</button>
      </div>
    `;
  }).join('');

  return sectionCardMini(title, `<div class="list">${list}</div>`);
}

