function wallViewPillHtml(active: WallViewMode): string {
  const mk = (mode: WallViewMode, label: string) =>
    `<button class="actionBtn${active === mode ? ' is-active' : ''}" type="button" data-wall-view="${escH(mode)}"${active === mode ? ' aria-current="page"' : ''}>${escH(label)}</button>`;
  return `${mk('posts', t('report.common.wallViewPosts'))} ${mk('engagement', t('report.common.wallViewEngagement'))} ${mk('actors', t('report.common.wallViewActors'))}`;
}

function wallFmtTs(ts: any): string {
  const n = Number(ts);
  return Number.isFinite(n) && n > 0 ? new Date(n * 1000).toLocaleString() : '—';
}

function wallEntityMeta(bundle: VkXtractBundle, id: number): { name: string; photo: string } {
  const pack = getFriendMetaPack(bundle);
  const resolvedAll = getResolvedUsersGlobal(bundle);
  const userMap = new Map<number, any>();
  for (const u of resolvedAll) {
    const uid = Number(u?.id);
    if (Number.isFinite(uid)) userMap.set(uid, u);
  }

  const abs = id < 0 ? Math.abs(id) : id;
  const resolved = userMap.get(id) || userMap.get(abs);
  const friend = (id > 0 && pack.metaMap.has(abs)) ? pack.metaMap.get(abs) : null;
  const entity = resolved || friend || null;

  return {
    name: entityDisplayName(id, entity),
    photo: entityPhoto(entity)
  };
}

function wallDailyBarsHtml(posts: any[]): string {
  const buckets = new Map<string, number>();
  for (const p of posts) {
    const ts = Number(p?.date);
    if (!Number.isFinite(ts) || ts <= 0) continue;
    const d = new Date(ts * 1000);
    const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
    buckets.set(key, (buckets.get(key) || 0) + 1);
  }

  const rows = Array.from(buckets.entries())
    .sort((a, b) => a[0].localeCompare(b[0]))
    .slice(-14);

  if (!rows.length) return `<div class="empty">${escH(t('report.common.noDatedPostsRecency'))}</div>`;

  const max = Math.max(...rows.map(([, v]) => v), 1);
  return rows.map(([day, count]) => {
    const pct = Math.max(8, Math.round((count / max) * 100));
    return `
      <div style="display:grid;grid-template-columns:94px 1fr 44px;gap:10px;align-items:center;margin-top:8px;">
        <div class="muted">${escH(day)}</div>
        <div style="height:10px;border-radius:999px;background:rgba(255,255,255,0.08);overflow:hidden;">
          <div style="height:10px;width:${pct}%;border-radius:999px;background:linear-gradient(90deg, rgba(99,102,241,0.95), rgba(59,130,246,0.92));"></div>
        </div>
        <div class="muted" style="text-align:right;">${escH(String(count))}</div>
      </div>
    `;
  }).join('');
}

function wallTopPostsHtml(posts: any[], metric: 'likes' | 'comments', limit = 8): string {
  const sorted = posts.slice().sort((a, b) => {
    const av = Number(metric === 'likes' ? a?.likes?.count : a?.comments?.count) || 0;
    const bv = Number(metric === 'likes' ? b?.likes?.count : b?.comments?.count) || 0;
    return bv - av;
  }).slice(0, limit);

  if (!sorted.length) return `<div class="empty">${escH(t('report.common.noPostsAvailable'))}</div>`;

  return sorted.map((p) => {
    const pid = Number(p?.id);
    const value = Number(metric === 'likes' ? p?.likes?.count : p?.comments?.count) || 0;
    const text = String(p?.text || '').replace(/\s+/g, ' ').trim();
    const excerpt = text ? (text.length > 110 ? `${text.slice(0, 110).trim()}…` : text) : (wallAttachmentModels(p).length ? t('report.common.attachmentOnlyPost') : t('report.common.wallPostLabel', { id: String(pid) }));
    return `
      <div class="listRow" data-wall-open-post="1" data-post-id="${escH(String(pid))}" style="cursor:pointer;">
        <div class="listTitle">${escH(excerpt)}</div>
        <div class="listMeta">${metric === 'likes' ? '❤️' : '💬'} ${escH(String(value))} • ${escH(t('report.common.wallPostLabel', { id: String(pid) }))}</div>
      </div>
    `;
  }).join('');
}

function wallOutboundDomainsHtml(posts: any[], limit = 12): string {
  const domainMap = new Map<string, { count: number; postIds: number[] }>();

  const touch = (domain: string, postId: number) => {
    if (!domain) return;
    const cur = domainMap.get(domain) || { count: 0, postIds: [] };
    cur.count++;
    if (!cur.postIds.includes(postId)) cur.postIds.push(postId);
    domainMap.set(domain, cur);
  };

  for (const p of posts) {
    const pid = Number(p?.id);
    if (!Number.isFinite(pid) || pid <= 0) continue;

    for (const d of wallExtractDomains(String(p?.text || ''))) touch(d, pid);

    for (const item of wallAttachmentModels(p)) {
      const d = wallDomainFromUrl(item.href);
      if (d) touch(d, pid);
    }
  }

  const rows = Array.from(domainMap.entries())
    .sort((a, b) => (b[1].count - a[1].count) || a[0].localeCompare(b[0]))
    .slice(0, limit);

  if (!rows.length) return `<div class="empty">${escH(t('report.common.noOutboundDomainsDetected'))}</div>`;

  return rows.map(([domain, rec]) => {
    const examples = rec.postIds.slice(0, 3).map((pid) =>
      `<span class="chip" data-wall-open-post="1" data-post-id="${escH(String(pid))}" style="cursor:pointer;">Post #${escH(String(pid))}</span>`
    ).join(' ');
    return `
      <div class="listRow">
        <div class="listTitle">${escH(domain)}</div>
        <div class="listMeta">${escH(t('report.common.seenCountTimes', { count: String(rec.count) }))}</div>
        <div style="margin-top:6px;display:flex;gap:6px;flex-wrap:wrap;">${examples}</div>
      </div>
    `;
  }).join('');
}

function wallTopActorsHtml(resp: WallSnapResp, bundle: VkXtractBundle, limit = 10): string {
  const actors = Array.isArray(resp?.observed?.actors) ? resp.observed!.actors as any[] : [];
  const rows = actors.slice().sort((a, b) => {
    const sa = Number(a?.comments ?? 0) + Number(a?.likes ?? 0);
    const sb = Number(b?.comments ?? 0) + Number(b?.likes ?? 0);
    return sb - sa;
  }).slice(0, limit);

  if (!rows.length) return `<div class="empty">${escH(t('report.common.noActorsCapturedSnapshot'))}</div>`;

  return rows.map((a) => {
    const id = Number(a?.id);
    const meta = wallEntityMeta(bundle, id);
    const total = Number(a?.comments ?? 0) + Number(a?.likes ?? 0);
    return `
      <div class="listRow" data-wall-open-actor="1" data-actor-id="${escH(String(id))}" style="cursor:pointer;">
        <div class="listTitle">${escH(meta.name)}</div>
        <div class="listMeta">${escH(t('report.common.interactionsLabel'))} ${escH(String(total))} • ❤️ ${escH(String(Number(a?.likes ?? 0)))} • 💬 ${escH(String(Number(a?.comments ?? 0)))} • ${escH(t('report.common.userId'))} ${escH(String(id))}</div>
      </div>
    `;
  }).join('');
}

