function openLcEdgeModal(scope: 'photo' | 'video' | 'observed', edgeId: string) {
  const st = getLcState(scope);
  const info = st.edgeInfo?.[edgeId];
  if (!info) return;

  const { modal, body } = ensureLcModal();
  if (!modal || !body) return;

  const b = bundleCache;
  const edgeActorName = (() => {
    if (!b) return info.uId < 0 ? `${t('report.common.communityLabel')} ${Math.abs(info.uId)}` : `${t('report.common.user')} ${Math.abs(info.uId)}`;
    if (scope === 'observed') return observedActorContext(b, info.uId).name;
    if (info.uId < 0) {
      const g = findResolvedGroup(b, Math.abs(info.uId));
      return entityDisplayName(-Math.abs(info.uId), g || null);
    }
    return userLabel(findResolvedUser(b, Math.abs(info.uId)) || null, Math.abs(info.uId), b).name;
  })();

  const uName = escLite(edgeActorName);
  const uUrl = info.uId < 0 ? `https://vk.com/club${Math.abs(info.uId)}` : `https://vk.com/id${Math.abs(info.uId)}`;

  const mUrl = scope === 'photo'
    ? `https://vk.com/photo${info.ownerId}_${info.itemId}`
    : scope === 'video'
      ? `https://vk.com/video${info.ownerId}_${info.itemId}`
      : `https://vk.com/wall${info.ownerId}_${info.itemId}`;

  const pills: string[] = [];
  if (info.liked) pills.push(pill(t('report.common.likes'), 'ok'));
  if (info.copied) pills.push(pill(scope === 'observed' ? t('report.common.repostCopyAction') : t('report.common.repostAction'), 'ok'));
  if (info.commentCount) pills.push(pill(t('report.common.commentTimes', { count: String(info.commentCount) }), 'ok'));
  if (Number(info.replyCount || 0) > 0) pills.push(pill(t('report.common.replyTimes', { count: String(Number(info.replyCount || 0)) }), 'ok'));
  if (!pills.length) pills.push(pill(t('report.common.noActionsCaptured'), 'muted'));

  const commentHtml = info.comments && info.comments.length
    ? `<div class="list" style="margin-top:10px;">${info.comments.slice(0, 14).map((c) => {
        const txt = String(c.text || '').trim();
        const when = c.date ? new Date(c.date * 1000).toISOString().slice(0, 10) : '';
        return `<div class="listRow"><div class="listTitle">${escLite(txt || t('report.common.noTextLabel'))}</div><div class="listMeta">${escLite(when)}</div></div>`;
      }).join('')}</div>`
    : `<div class="empty" style="margin-top:10px;">${escLite(t('report.common.noCommentTextCapturedForEdge'))}</div>`;

  body.innerHTML = `
    <div class="sec-title white" style="margin: 4px 0 10px 0;">
      <span class="sub-title">${escLite(t('report.common.linkEvidence'))}</span>
      <h2 class="title" style="font-size:18px;">${uName} ↔ ${escLite(scope === 'observed' ? `post ${info.mKey}` : `${scope} ${info.mKey}`)}</h2>
    </div>

    <div class="ovCard">
      <div style="display:flex; gap:10px; flex-wrap:wrap; align-items:center;">
        ${pills.join(' ')}
      </div>
      <div style="margin-top:10px; display:flex; gap:12px; flex-wrap:wrap;">
        <a class="gridLinkBtn" href="${escLite(uUrl)}" target="_blank" rel="noreferrer">${escLite(t('report.common.openExternal'))}</a>
        <a class="gridLinkBtn" href="${escLite(mUrl)}" target="_blank" rel="noreferrer">${escLite(t('report.common.openExternal'))}</a>
      </div>
      ${commentHtml}
      <div class="muted" style="margin-top:10px;">${escLite(scope === 'observed' ? t('report.common.capturedFromWallSnapshotEvidence') : t('report.common.capturedFromApiEnrichment'))}</div>
    </div>
  `;

  modal.classList.add('open');
  modal.setAttribute('aria-hidden', 'false');
}

function buildLinkChart(scope: 'photo' | 'video') {
  const b = bundleCache;
  if (!b) return;
  const enrich = getEnrich(b, scope);
  if (!enrich) return;

  const container = document.querySelector(`[data-linkchart="${scope}"]`) as HTMLElement | null;
  if (!container) return;

  const mediaObj = scope === 'photo' ? enrich?.media?.photos : enrich?.media?.videos;
  if (!mediaObj || typeof mediaObj !== 'object') {
    container.innerHTML = `<div class="empty">${escHtml(t('report.common.noMediaEngagementMapFound'))}</div>`;
    return;
  }

  const st = getLcState(scope);
  st.mode = 'vis';

  const hasMountedHost = !!container.querySelector(`[data-lc-vis="${scope}"]`);
  if (st.vis?.network && !hasMountedHost) {
    try { st.vis.network.destroy?.(); } catch {}
    st.vis = undefined;
  }

  if (!lcVisAvailable()) {
    container.innerHTML = `<div style="padding:10px 12px;color:rgba(231,238,252,0.92);border:1px solid rgba(255,255,255,0.12);border-radius:12px;background:rgba(239,68,68,0.14);">
      ${escHtml(t('report.common.linkChartNotLoaded'))}
    </div>`;
    toast('Link chart failed: vis-network not loaded', 'bad');
    st.generated = false;
    return;
  }

  // Select top 30×30
  const topUsers = Array.isArray(enrich?.users?.top_total) ? enrich.users.top_total.slice(0, 30) : [];
  const topHot = Array.isArray(enrich?.hotspots) ? enrich.hotspots.slice(0, 30) : [];

  const users: number[] = topUsers.map((x: any) => Number(x?.id)).filter((n: number) => Number.isFinite(n) && n !== 0);
  const mediaKeys: string[] = topHot.map((h: any) => `${Number(h?.owner_id)}_${Number(h?.id)}`).filter((k: string) => k && !k.includes('NaN'));

  if (!users.length || !mediaKeys.length) {
    container.innerHTML = `<div class="empty">${escHtml(t('report.common.notEnoughDataGenerateChart'))}</div>`;
    return;
  }

  const edges: LcEdgeInfo[] = [];
  const edgeInfo: Record<string, LcEdgeInfo> = {};
  const edgeEnds: Record<string, { a: string; b: string }> = {};
  const adj = new Map<string, Set<string>>();

  const addAdj = (a: string, b: string) => {
    if (!adj.has(a)) adj.set(a, new Set());
    adj.get(a)!.add(b);
  };

  for (const mk of mediaKeys) {
    const m = (mediaObj as any)[mk];
    if (!m || m.denied) continue;

    const likeSet = new Set<number>((Array.isArray(m.likes_ids) ? m.likes_ids : []).map((x: any) => Number(x)).filter((n: number) => Number.isFinite(n) && n !== 0));
    const copySet = new Set<number>((Array.isArray(m.copies_ids) ? m.copies_ids : []).map((x: any) => Number(x)).filter((n: number) => Number.isFinite(n) && n !== 0));
    const commentItemsRaw = Array.isArray(m.comment_items) ? m.comment_items : [];

    for (const uid of users) {
      const liked = likeSet.has(uid);
      const copied = copySet.has(uid);

      const commentsForRaw = commentItemsRaw.filter((c: any) => Number(c?.from_id) === uid);
      const comments = commentsForRaw.slice(0, 16).map((c: any) => ({ text: String(c?.text || ''), date: Number(c?.date || 0) }));
      const commentCount = commentsForRaw.length;

      if (!liked && !copied && !commentCount) continue;

      const a = `u:${uid}`;
      const b2 = `m:${mk}`;
      const edgeId = `${a}|${b2}`;

      const ownerId = Number(m?.owner_id ?? Number(String(mk).split('_')[0]));
      const itemId = Number(m?.id ?? Number(String(mk).split('_')[1]));

      const info: LcEdgeInfo = { edgeId, a, b: b2, uId: uid, mKey: mk, ownerId, itemId, scope, liked, copied, commentCount, comments };

      edges.push(info);
      edgeInfo[edgeId] = info;
      edgeEnds[edgeId] = { a, b: b2 };
      addAdj(a, b2);
      addAdj(b2, a);
    }
  }

  if (!edges.length) {
    container.innerHTML = `<div class="empty">${escHtml(t('report.common.noEdgesFoundEnrichMore'))}</div>`;
    return;
  }

  const adjObj: Record<string, string[]> = {};
  for (const [k, s] of adj.entries()) adjObj[k] = Array.from(s);

  st.edgeInfo = edgeInfo;
  st.edgeEnds = edgeEnds;
  st.adj = adjObj;

  const newKey = `${scope}|${users.join(',')}|${mediaKeys.join(',')}`;
  const fresh = st.dataKey !== newKey;
  st.dataKey = newKey;
  if (fresh) { st.sel = ''; st.selKeys = []; }

  // Only include nodes that participate in at least one edge (prevents orphan media/users)
  const usedUsers = new Set<number>();
  const usedMedia = new Set<string>();
  for (const e of edges) {
    usedUsers.add(Number(e.uId));
    usedMedia.add(String(e.mKey));
  }

  const nodeUsers = users.filter((uid) => usedUsers.has(uid));
  const nodeMediaKeys = mediaKeys.filter((mk) => usedMedia.has(mk));

  const nodesVis: Array<{ key: string; kind: 'user' | 'media'; label: string; thumb?: string }> = [];

  for (const uid of nodeUsers) {
    const u0 = findResolvedUser(b, uid);
    const ul = userLabel(u0, uid, b);
    nodesVis.push({ key: `u:${uid}`, kind: 'user', label: ul.name });
  }

  const mediaMap = getMediaMap(b, scope);
  const thumbOfMedia = (key: string) => {
    const base = mediaMap.get(key) || (mediaObj as any)[key] || null;
    return scope === 'photo' ? bestPhotoUrlJs(base || {}) : videoThumbUrlJs(base || {});
  };

  for (const mk of nodeMediaKeys) {
    nodesVis.push({ key: `m:${mk}`, kind: 'media', label: `${scope}${mk}`, thumb: thumbOfMedia(mk) });
  }

    const ok = (st.vis?.network ? lcVisUpsert(scope, st, nodesVis, edges) : lcVisBuild(
    scope,
    container,
    nodesVis,
    edges,
    st,
    {
      // Edge click -> evidence modal
      onEdge: (edgeId) => { if (edgeId) openLcEdgeModal(scope, String(edgeId)); },

      // Selection change (supports ctrl+click multiselect)
      onSelection: (nodeIds, lastId) => {
        const ids = Array.isArray(nodeIds) ? nodeIds.map((x) => String(x)) : [];
        st.selKeys = ids;
        st.sel = String(lastId || ids[ids.length - 1] || ids[0] || '');
        lcVisApplyFocus(scope, st);
      },

      // Double click -> open lightbox
      onNodeDbl: (nodeId) => {
        const k = String(nodeId || '');
        if (k.startsWith('m:')) openLcBoxMedia(scope, k.slice(2));
        else if (k.startsWith('u:')) {
          const uid = Number(k.slice(2));
          if (Number.isFinite(uid)) openLcBoxUser(scope, uid);
        }
      },

      // Hover media -> different accent colour
      onHoverMedia: (id) => {
        st.hoverKey = String(id || '');
        lcVisApplyFocus(scope, st);
      },
      onBlurMedia: () => {
        st.hoverKey = '';
        lcVisApplyFocus(scope, st);
      },

      onClear: () => {
        st.sel = '';
        st.selKeys = [];
        try { (st.vis?.network as any)?.unselectAll?.(); } catch {}
        lcVisApplyFocus(scope, st);
      }
    }
  ));

  if (!ok) {
    container.innerHTML = `<div style="padding:10px 12px;color:rgba(231,238,252,0.92);border:1px solid rgba(255,255,255,0.12);border-radius:12px;background:rgba(239,68,68,0.14);">
      ${escHtml(t('report.common.linkChartInitFailed'))}
    </div>`;
    toast('Link chart failed: vis-network init error', 'bad');
    st.generated = false;
    return;
  }

  st.generated = true;
  lcVisApplyFocus(scope, st);
}

function jumpToMedia(kind: 'photo' | 'video' | 'clip', mediaKey: string) {
  const key = String(mediaKey || '');
  if (!key) return;

  const tryOpen = (tabId: string, kindSel: string): boolean => {
    const tab = document.getElementById(tabId) as HTMLInputElement | null;
    if (tab) tab.checked = true;

    const btn = document.querySelector(
      `button[data-media-toggle="1"][data-media-wide="1"][data-media-kind="${kindSel}"][data-media-key="${cssEscAttr(key)}"]`
    ) as HTMLButtonElement | null;

    if (!btn) return false;

    const album = btn.closest('details') as HTMLDetailsElement | null;
    if (album && (album as any).open === false) album.open = true;

    try { btn.scrollIntoView({ block: 'center', behavior: 'smooth' }); } catch {}
    try { btn.click(); } catch {}
    return true;
  };

  if (kind === 'photo') {
    window.setTimeout(() => {
      if (!tryOpen('tab-photos', 'photo')) toast(t('report.common.mediaCardNotFoundCurrentView'), 'bad');
    }, 60);
    return;
  }

  const openWithinVideos = (preferredKinds: Array<'video' | 'clip'>) => {
    const tabV = document.getElementById('tab-videos') as HTMLInputElement | null;
    if (tabV) tabV.checked = true;

    window.setTimeout(() => {
      for (const kindSel of preferredKinds) {
        if (tryOpen('tab-videos', kindSel)) return;
      }
      toast('Media card not found in the current report view.', 'bad');
    }, 60);
  };

  if (kind === 'clip') {
    openWithinVideos(['clip', 'video']);
    return;
  }

  openWithinVideos(['video', 'clip']);
}

