      const drop = zoomReset.closest('.mediaDrop') as HTMLElement | null;
      const wrap = drop ? (drop.querySelector('.mediaZoomWrap') as HTMLElement | null) : null;
      if (wrap) setZoom(wrap, 1);
      return;
