      const source = String(activityJumpHit.getAttribute('data-activity-source') || 'wall');
      const pid = Number(activityJumpHit.getAttribute('data-post-id') || 0);
      const cid = Number(activityJumpHit.getAttribute('data-comment-id') || 0);
