      if (!Number.isFinite(pid) || pid <= 0 || !bundleCache) return;

      (window as any).__vkxWallSelPostId = pid;
      (window as any).__vkxWallOpenPostId = pid;
      (window as any).__vkxWallInteractionTab = tab;

      const resp = getWallSnapshot(bundleCache);
